import {
  Injectable,
  NotFoundException,
  BadRequestException,
} from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { DataSource, Repository } from 'typeorm';
import { JobEntity, JobStatus } from '../entities/job.entity';
import { JobStatusHistoryEntity } from '../entities/job-status-history.entity';
import { JobFilterDto } from '../dto/job-filter.dto';
import { getPaginatedResult } from '../../common/utils/pagination.util';

@Injectable()
export class AdminJobsService {
  constructor(
    @InjectRepository(JobEntity)
    private readonly jobRepository: Repository<JobEntity>,
    @InjectRepository(JobStatusHistoryEntity)
    private readonly historyRepo: Repository<JobStatusHistoryEntity>,
    private readonly dataSource: DataSource,
  ) {}

  async approveJob(jobId: number) {
    const job = await this.jobRepository.findOne({ where: { id: jobId } });
    if (!job) throw new NotFoundException('Không tìm thấy tin');

    if (job.status === (JobStatus.PUBLISHED as string)) {
      throw new BadRequestException('Tin đã được duyệt trước đó');
    }

    const oldStatus = job.status;

    await this.dataSource.transaction(async (manager) => {
      await manager.update(JobEntity, jobId, {
        status: JobStatus.PUBLISHED,
        rejectionReason: null,
      });

      await manager.save(
        JobStatusHistoryEntity,
        manager.create(JobStatusHistoryEntity, {
          jobId,
          oldStatus,
          newStatus: JobStatus.PUBLISHED,
        }),
      );
    });

    return { message: 'Đã duyệt tin tuyển dụng' };
  }

  async rejectJob(jobId: number, reason: string) {
    const job = await this.jobRepository.findOne({ where: { id: jobId } });
    if (!job) throw new NotFoundException('Không tìm thấy tin');

    if (job.status === (JobStatus.REJECTED as string)) {
      throw new BadRequestException('Tin đã bị từ chối trước đó');
    }

    const oldStatus = job.status;

    await this.dataSource.transaction(async (manager) => {
      await manager.update(JobEntity, jobId, {
        status: JobStatus.REJECTED,
        rejectionReason: reason,
      });

      await manager.save(
        JobStatusHistoryEntity,
        manager.create(JobStatusHistoryEntity, {
          jobId,
          oldStatus,
          newStatus: JobStatus.REJECTED,
          reason,
        }),
      );
    });

    return { message: 'Đã từ chối tin tuyển dụng' };
  }

  async getAdminJobs(filterDto: JobFilterDto) {
    const { page = 1, limit = 10, keyword, status } = filterDto;

    const qb = this.jobRepository
      .createQueryBuilder('job')
      .leftJoinAndSelect('job.company', 'company')
      .leftJoinAndSelect('job.category', 'category');

    if (keyword) {
      qb.andWhere('job.title ILIKE :keyword', { keyword: `%${keyword}%` });
    }

    if (status) {
      qb.andWhere('job.status = :status', { status });
    }

    qb.orderBy('job.createdAt', 'DESC');

    return getPaginatedResult(qb, page, limit);
  }

  async getAdminJobHistory(jobId: number) {
    return this.historyRepo.find({
      where: { jobId },
      order: { createdAt: 'DESC' },
    });
  }
}

import { Injectable } from '@nestjs/common';

@Injectable()
export class AppService {
  getHello(): string {
    return 'Hello World!';
  }
}

import {
  Injectable,
  ConflictException,
  Inject,
  forwardRef,
} from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository } from 'typeorm';
import { UserEntity, UserRole } from '../users/entities/user.entity';
import { RegisterDto } from './dto/register.dto';
import { RegisterEmployerDto } from './dto/register-employer.dto';
import { CandidateProfileService } from '../candidates/services/candidate-profile.service';
import { LoginDto } from './dto/login.dto';
import * as bcrypt from 'bcrypt';
import { JwtService } from '@nestjs/jwt';
import { ConfigService } from '@nestjs/config';
import { RefreshTokenEntity } from './entities/refresh-token.entity';
import { Response } from 'express';

@Injectable()
export class AuthService {
  constructor(
    @InjectRepository(UserEntity)
    private readonly userRepository: Repository<UserEntity>,
    @Inject(forwardRef(() => CandidateProfileService))
    private readonly candidateProfileService: CandidateProfileService,
    @InjectRepository(RefreshTokenEntity)
    private readonly refreshTokenRepository: Repository<RefreshTokenEntity>,
    private readonly jwtService: JwtService,
    private readonly configService: ConfigService,
  ) {}

  async register(registerDto: RegisterDto) {
    const { email, password, firstName, lastName, phone, provinceId } =
      registerDto;

    // Kiểm tra email đã tồn tại chưa
    const existingUser = await this.userRepository.findOne({
      where: { email },
    });

    if (existingUser) {
      throw new ConflictException('Email đã được sử dụng');
    }

    // Tạo user mới - role mặc định là candidate
    const user = this.userRepository.create({
      email,
      password,
      role: UserRole.CANDIDATE,
    });
    const savedUser = await this.userRepository.save(user);

    const candidate = await this.candidateProfileService.createCoreProfile({
      userId: savedUser.id,
      firstName,
      lastName,
      phone,
      provinceId,
    });

    return {
      message: 'User registered successfully',
      user: {
        id: savedUser.id,
        email: savedUser.email,
        role: savedUser.role,
        fullName: candidate.fullName,
        phone: candidate.phone,
        provinceId: candidate.provinceId,
      },
    };
  }

  async registerEmployer(dto: RegisterEmployerDto) {
    const { email, password } = dto;

    const existingUser = await this.userRepository.findOne({
      where: { email },
    });

    if (existingUser) {
      throw new ConflictException('Email đã được sử dụng');
    }

    const user = this.userRepository.create({
      email,
      password,
      role: UserRole.EMPLOYER,
    });
    const savedUser = await this.userRepository.save(user);

    return {
      message: 'Tài khoản Employer được tạo thành công',
      user: {
        id: savedUser.id,
        email: savedUser.email,
        role: savedUser.role,
      },
    };
  }

  async validateUser({ email, password }: LoginDto) {
    const user = await this.userRepository.findOne({
      where: { email },
      relations: ['candidate'],
    });
    if (!user) {
      return null;
    }
    const isPasswordValid = await bcrypt.compare(password, user.password);
    if (!isPasswordValid) {
      return null;
    }
    return user;
  }

  async generateTokenPair(user: UserEntity, jti?: string) {
    const payload = {
      id: user.id,
      email: user.email,
      role: user.role,
      ...(user.candidate ? { candidateId: user.candidate.id } : {}),
    };

    const [accessToken, refreshToken] = await Promise.all([
      this.jwtService.signAsync(payload, {
        secret: this.configService.get<string>('JWT_SECRET'),
        expiresIn: this.configService.get<string>(
          'JWT_EXPIRES_TIME',
        ) as import('@nestjs/jwt').JwtSignOptions['expiresIn'],
      }),
      this.jwtService.signAsync(
        { ...payload, jti },
        {
          secret: this.configService.get<string>('JWT_REFRESH_SECRET'),
          expiresIn: this.configService.get<string>(
            'JWT_REFRESH_EXPIRES_TIME',
          ) as import('@nestjs/jwt').JwtSignOptions['expiresIn'],
        },
      ),
    ]);

    return {
      access_token: accessToken,
      refresh_token: refreshToken,
    };
  }

  async storeRefreshToken(
    userId: number,
    token: string,
    jti: string,
    userAgent?: string,
    ipAddress?: string,
  ) {
    const hashedToken = await bcrypt.hash(token, 10);
    const expiresAt = new Date();
    // Giả sử refresh token hết hạn sau 7 ngày (đồng bộ với JWT config)
    expiresAt.setDate(expiresAt.getDate() + 7);

    const refreshToken = this.refreshTokenRepository.create({
      id: jti,
      userId,
      token: hashedToken,
      expiresAt,
      userAgent,
      ipAddress,
    });

    await this.refreshTokenRepository.save(refreshToken);
  }

  async refreshTokens(
    userId: number,
    jti: string,
    rawRefreshToken: string,
    userAgent?: string,
    ipAddress?: string,
  ) {
    const user = await this.userRepository.findOne({
      where: { id: userId },
      relations: ['candidate'],
    });
    if (!user) throw new ConflictException('User not found');

    // O(1) Lookup: Tìm chính xác bản ghi theo JTI (ID)
    const tokenRecord = await this.refreshTokenRepository.findOne({
      where: { id: jti, userId, isRevoked: false },
    });

    if (!tokenRecord) {
      throw new ConflictException('Invalid Refresh Token');
    }

    // Verify hash (Security Layer)
    const isMatch = await bcrypt.compare(rawRefreshToken, tokenRecord.token);
    if (!isMatch) {
      throw new ConflictException('Invalid Refresh Token Content');
    }

    // Xoay vòng (Rotation): Xóa bản ghi cũ
    await this.refreshTokenRepository.remove(tokenRecord);

    // Tạo cặp mới
    const newJti = crypto.randomUUID();
    const tokens = await this.generateTokenPair(user, newJti);
    await this.storeRefreshToken(
      user.id,
      tokens.refresh_token,
      newJti,
      userAgent,
      ipAddress,
    );

    return tokens;
  }

  async logout(userId: number, jti?: string) {
    if (!jti) return;
    await this.refreshTokenRepository.delete({ id: jti, userId });
  }

  setRefreshTokenCookie(res: Response, token: string) {
    res.cookie('refresh_token', token, {
      httpOnly: true,
      secure: process.env.NODE_ENV === 'production',
      sameSite: 'strict',
      maxAge: 7 * 24 * 60 * 60 * 1000, // 7 ngày
    });
  }

  clearRefreshTokenCookie(res: Response) {
    res.clearCookie('refresh_token');
  }

  async login(user: UserEntity) {
    const jti = crypto.randomUUID();
    const tokens = await this.generateTokenPair(user, jti);
    return {
      access_token: tokens.access_token,
      refresh_token: tokens.refresh_token,
      jti,
      user: {
        id: user.id,
        email: user.email,
        role: user.role,
      },
    };
  }

  async loginAdmin(dto: LoginDto) {
    // 1. Tìm user theo email
    const user = await this.userRepository.findOne({
      where: { email: dto.email },
    });

    // 2. Chặn sớm nếu không phải Admin hoặc không tồn tại (Security Requirement)
    if (!user || user.role !== UserRole.ADMIN) {
      throw new ConflictException('Tài khoản không có quyền quản trị');
    }

    // 3. So khớp password (chỉ dành cho Admin)
    const isPasswordValid = await bcrypt.compare(dto.password, user.password);
    if (!isPasswordValid) {
      throw new ConflictException('Mật khẩu không chính xác');
    }

    // 4. Trả về Token Admin
    const result = await this.login(user); // Use unified login to get tokens + jti
    return result;
  }
}

import {
  Injectable,
  NotFoundException,
  BadRequestException,
  ConflictException,
  Logger,
} from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { DataSource, Repository } from 'typeorm';
import {
  JobApplicationEntity,
  ApplicationStatus,
} from './entities/job-application.entity';
import { ApplicationStatusHistoryEntity } from './entities/application-status-history.entity';
import { CandidateEntity } from '../candidates/entities/candidate.entity';
import { JobEntity, JobStatus } from '../jobs/entities/job.entity';
import { ApplyJobDto } from './dto/apply-job.dto';
import { ApplicationFilterDto } from './dto/application-filter.dto';
import { ConfigService } from '@nestjs/config';
import { GoogleGenerativeAI } from '@google/generative-ai';
import {
  MatchScoreResult,
  CvMatchScoreResult,
} from './interfaces/matching.interface';
import { CANDIDATE_MATCH_SCORE_PROMPT } from './prompts/candidate-match-score.prompt';
import { CV_MATCH_SCORE_PROMPT } from './prompts/cv-match-score.prompt';

@Injectable()
export class CandidateApplicationsService {
  private readonly logger = new Logger(CandidateApplicationsService.name);
  private genAI: GoogleGenerativeAI;
  private readonly aiModel: string;

  constructor(
    @InjectRepository(JobApplicationEntity)
    private readonly applicationRepo: Repository<JobApplicationEntity>,
    @InjectRepository(ApplicationStatusHistoryEntity)
    private readonly historyRepo: Repository<ApplicationStatusHistoryEntity>,
    @InjectRepository(CandidateEntity)
    private readonly candidateRepo: Repository<CandidateEntity>,
    @InjectRepository(JobEntity)
    private readonly jobRepo: Repository<JobEntity>,
    private readonly configService: ConfigService,
    private readonly dataSource: DataSource,
  ) {
    const apiKey = this.configService.get<string>('GEMINI_API_KEY');
    if (apiKey) {
      this.genAI = new GoogleGenerativeAI(apiKey);
    }
    this.aiModel = this.configService.get<string>(
      'GEMINI_MODEL',
      'gemini-2.5-flash',
    );
  }

  async apply(userId: number, jobId: number, dto: ApplyJobDto) {
    const candidate = await this.findCandidateByUserId(userId);

    if (!candidate.cvUrl) {
      throw new BadRequestException(
        'Vui lòng tải lên CV trước khi ứng tuyển. Truy cập API POST /api/candidates/cv để upload.',
      );
    }

    const job = await this.jobRepo.findOne({ where: { id: jobId } });
    if (!job) {
      throw new NotFoundException('Tin tuyển dụng không tồn tại');
    }

    if (job.status !== (JobStatus.PUBLISHED as string)) {
      throw new BadRequestException(
        'Tin tuyển dụng chưa được phát hành hoặc đã đóng',
      );
    }

    if (job.deadline && new Date(job.deadline) < new Date()) {
      throw new BadRequestException('Tin tuyển dụng đã hết hạn nộp hồ sơ');
    }

    const existing = await this.applicationRepo.findOne({
      where: { jobId, candidateId: candidate.id },
    });

    if (existing) {
      if (existing.status === (ApplicationStatus.WITHDRAWN as string)) {
        await this.dataSource.transaction(async (manager) => {
          existing.status = ApplicationStatus.APPLIED;
          existing.cvUrlSnapshot = candidate.cvUrl;
          existing.coverLetter = dto.coverLetter ?? null;
          existing.rejectionReason = null;
          existing.employerNote = null;
          existing.matchScore = null;
          existing.matchReasoning = null;
          existing.cvMatchScore = null;
          existing.cvMatchReasoning = null;

          const savedApp = await manager.save(JobApplicationEntity, existing);

          const history = manager.create(ApplicationStatusHistoryEntity, {
            applicationId: savedApp.id,
            oldStatus: ApplicationStatus.WITHDRAWN,
            newStatus: ApplicationStatus.APPLIED,
            reason: null,
            changedById: userId,
          });
          await manager.save(ApplicationStatusHistoryEntity, history);
        });

        // Fire and forget AI grading
        this.calculateAiMatchScore(existing.id).catch((err: unknown) => {
          this.logger.error(
            'Error calculating AI match score for re-apply',
            err instanceof Error ? err.stack : String(err),
          );
        });

        return {
          message:
            'Bạn đã từng ứng tuyển công việc này trước đó. Đơn ứng tuyển đã được gửi lại thành công.',
          applicationId: existing.id,
          reapplied: true,
        };
      }

      throw new ConflictException(
        'Bạn đã ứng tuyển công việc này rồi. Không thể nộp đơn trùng lặp.',
      );
    }

    let applicationId: number;

    await this.dataSource.transaction(async (manager) => {
      const application = manager.create(JobApplicationEntity, {
        jobId,
        candidateId: candidate.id,
        cvUrlSnapshot: candidate.cvUrl,
        coverLetter: dto.coverLetter,
        status: ApplicationStatus.APPLIED,
      });
      const saved = await manager.save(JobApplicationEntity, application);
      applicationId = saved.id;

      const history = manager.create(ApplicationStatusHistoryEntity, {
        applicationId: saved.id,
        oldStatus: null,
        newStatus: ApplicationStatus.APPLIED,
        reason: null,
        changedById: userId,
      });
      await manager.save(ApplicationStatusHistoryEntity, history);
    });

    // Fire and forget AI grading
    this.calculateAiMatchScore(applicationId!).catch((err: unknown) => {
      this.logger.error(
        'Error calculating AI match score',
        err instanceof Error ? err.stack : String(err),
      );
    });

    return {
      message: 'Ứng tuyển thành công',
      applicationId: applicationId!,
      reapplied: false,
    };
  }

  async getMyApplications(userId: number, filterDto: ApplicationFilterDto) {
    const candidate = await this.findCandidateByUserId(userId);
    const { page = 1, limit = 10, status } = filterDto;

    const qb = this.applicationRepo
      .createQueryBuilder('app')
      .leftJoinAndSelect('app.job', 'job')
      .leftJoinAndSelect('job.company', 'company')
      .leftJoinAndSelect('job.province', 'province')
      .leftJoinAndSelect('job.category', 'category')
      .where('app.candidateId = :candidateId', {
        candidateId: candidate.id,
      });

    if (status) {
      qb.andWhere('app.status = :status', { status });
    }

    qb.orderBy('app.appliedAt', 'DESC');

    const skip = (page - 1) * limit;
    const [data, total] = await qb.skip(skip).take(limit).getManyAndCount();

    return { data, total, page, lastPage: Math.ceil(total / limit) };
  }

  async getMyApplicationDetail(userId: number, applicationId: number) {
    const candidate = await this.findCandidateByUserId(userId);

    const application = await this.applicationRepo.findOne({
      where: { id: applicationId, candidateId: candidate.id },
      relations: [
        'job',
        'job.company',
        'job.province',
        'job.category',
        'job.jobType',
        'statusHistory',
      ],
    });

    if (!application) {
      throw new NotFoundException('Đơn ứng tuyển không tồn tại');
    }

    return application;
  }

  async withdrawApplication(userId: number, applicationId: number) {
    const candidate = await this.findCandidateByUserId(userId);

    const application = await this.applicationRepo.findOne({
      where: { id: applicationId, candidateId: candidate.id },
    });

    if (!application) {
      throw new NotFoundException('Đơn ứng tuyển không tồn tại');
    }

    if (application.status === (ApplicationStatus.WITHDRAWN as string)) {
      throw new BadRequestException('Đơn ứng tuyển đã được rút trước đó');
    }

    const nonWithdrawableStatuses = [
      ApplicationStatus.OFFER as string,
      ApplicationStatus.HIRED as string,
    ];
    if (nonWithdrawableStatuses.includes(application.status)) {
      throw new BadRequestException(
        'Không thể rút đơn khi đã nhận đề nghị việc làm hoặc đã được tuyển dụng. Vui lòng liên hệ nhà tuyển dụng.',
      );
    }

    const oldStatus = application.status;
    application.status = ApplicationStatus.WITHDRAWN;

    await this.dataSource.transaction(async (manager) => {
      await manager.save(JobApplicationEntity, application);
      await manager.save(
        ApplicationStatusHistoryEntity,
        manager.create(ApplicationStatusHistoryEntity, {
          applicationId: application.id,
          oldStatus,
          newStatus: ApplicationStatus.WITHDRAWN,
          reason: 'Ứng viên tự rút đơn',
          changedById: userId,
        }),
      );
    });

    return { message: 'Đã rút đơn ứng tuyển thành công' };
  }

  private async findCandidateByUserId(userId: number) {
    const candidate = await this.candidateRepo.findOne({
      where: { userId },
    });
    if (!candidate) {
      throw new NotFoundException('Hồ sơ ứng viên không tồn tại');
    }
    return candidate;
  }

  private async calculateAiMatchScore(applicationId: number) {
    if (!this.genAI) {
      this.logger.warn('AI API key not configured. Skipping match score.');
      return;
    }

    const application = await this.applicationRepo.findOne({
      where: { id: applicationId },
      relations: [
        'job',
        'job.skills',
        'job.skills.skillMetadata',
        'candidate',
        'candidate.skills',
        'candidate.skills.skillMetadata',
        'candidate.educations',
        'candidate.workExperiences',
        'candidate.projects',
        'candidate.certificates',
      ],
    });

    if (!application) return;

    const jobData = {
      title: application.job.title,
      requirements: application.job.requirements,
      yearsOfExperience: application.job.yearsOfExperience,
      skillTags:
        application.job.skills?.map((s) => s.skillMetadata?.canonicalName) ||
        [],
    };

    const promises: Promise<void>[] = [];

    promises.push(this.calculateProfileScore(application, jobData));

    if (application.cvUrlSnapshot) {
      promises.push(this.calculateCvScore(application, jobData));
    }

    await Promise.allSettled(promises);
  }

  private async calculateProfileScore(
    application: JobApplicationEntity,
    jobData: Record<string, any>,
  ) {
    const candidateData = {
      yearsOfExperience: application.candidate.yearWorkingExperience,
      skills:
        application.candidate.skills?.map(
          (s) => s.skillMetadata?.canonicalName,
        ) || [],
      workExperiences:
        application.candidate.workExperiences?.map((we) => ({
          position: we.position,
          company: we.companyName,
          description: we.description,
        })) || [],
      projects:
        application.candidate.projects?.map((p) => ({
          name: p.name,
          description: p.description,
        })) || [],
      certificates:
        application.candidate.certificates?.map((c) => ({
          name: c.name,
        })) || [],
    };

    const prompt = CANDIDATE_MATCH_SCORE_PROMPT(jobData, candidateData);

    try {
      const model = this.genAI.getGenerativeModel({
        model: this.aiModel,
      });
      const result = await model.generateContent(prompt);
      const text = result.response.text().trim();

      const jsonMatch = text.match(/\{[\s\S]*\}/);
      if (!jsonMatch) {
        throw new Error('No JSON object found in AI response');
      }

      const parsed = JSON.parse(jsonMatch[0]) as MatchScoreResult;

      if (typeof parsed.matchScore === 'number') {
        // Fix Race Condition by updating only specific columns
        await this.applicationRepo.update(application.id, {
          matchScore: parsed.matchScore,
          matchReasoning: parsed.reasoning || text,
        });

        this.logger.log(
          'AI Profile Score calculated for App #' +
            application.id +
            ': ' +
            parsed.matchScore,
        );
      }
    } catch (error: unknown) {
      this.logger.error(
        'Failed to calculate AI Profile Score for application ' +
          application.id,
        error instanceof Error ? error.message : String(error),
      );
    }
  }

  private async calculateCvScore(
    application: JobApplicationEntity,
    jobData: Record<string, any>,
  ) {
    try {
      const fileData = await this.fetchBase64Cv(application.cvUrlSnapshot);
      if (!fileData) {
        this.logger.warn(
          'Không thể đọc file CV định dạng này cho App #' + application.id,
        );
        return;
      }

      const prompt = CV_MATCH_SCORE_PROMPT(jobData);
      const model = this.genAI.getGenerativeModel({
        model: this.aiModel,
      });

      const result = await model.generateContent([
        {
          inlineData: {
            data: fileData.base64,
            mimeType: fileData.mimeType,
          },
        },
        prompt,
      ]);

      const text = result.response.text().trim();

      const jsonMatch = text.match(/\{[\s\S]*\}/);
      if (!jsonMatch) {
        throw new Error('No JSON object found in AI CV response');
      }

      const parsed = JSON.parse(jsonMatch[0]) as CvMatchScoreResult;

      if (typeof parsed.cvMatchScore === 'number') {
        // Fix Race Condition by updating only specific columns
        await this.applicationRepo.update(application.id, {
          cvMatchScore: parsed.cvMatchScore,
          cvMatchReasoning: parsed.reasoning || text,
        });

        this.logger.log(
          'AI CV Score calculated for App #' +
            application.id +
            ': ' +
            parsed.cvMatchScore,
        );
      }
    } catch (error: unknown) {
      this.logger.error(
        'Failed to calculate AI CV Score for application ' + application.id,
        error instanceof Error ? error.message : String(error),
      );
    }
  }

  private async fetchBase64Cv(
    url: string | null,
  ): Promise<{ base64: string; mimeType: string } | null> {
    if (!url || !url.startsWith('http')) return null;

    // --- SSRF Protection Start ---
    const supabaseUrl = this.configService.get<string>('SUPABASE_PROJECT_URL');
    if (supabaseUrl) {
      try {
        const urlHost = new URL(url).host;
        const supabaseHost = new URL(supabaseUrl).host;
        if (urlHost !== supabaseHost) {
          this.logger.warn(
            `SSRF Blocked: URL host ${urlHost} does not match ${supabaseHost}`,
          );
          return null;
        }
      } catch {
        return null;
      }
    }
    // --- SSRF Protection End ---

    try {
      const res = await fetch(url);
      if (!res.ok) return null;

      const contentLength = res.headers.get('content-length');
      if (contentLength && parseInt(contentLength, 10) > 10 * 1024 * 1024) {
        this.logger.warn(`CV too large (${contentLength} bytes): ${url}`);
        return null; // Ignore files > 10MB
      }

      const mimeType = res.headers.get('content-type') || 'application/pdf';
      if (!mimeType.includes('pdf') && !mimeType.includes('image')) {
        return null;
      }

      const arrayBuffer = await res.arrayBuffer();
      const buffer = Buffer.from(arrayBuffer);
      return { base64: buffer.toString('base64'), mimeType };
    } catch (e: unknown) {
      this.logger.error('Fetch CV failed: ' + url, e);
      return null;
    }
  }
}

import {
  Injectable,
  NotFoundException,
  ForbiddenException,
  Logger,
} from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository } from 'typeorm';
import 'multer';
import { SupabaseService } from '../../storage/supabase.service';
import { CandidateEntity } from '../entities/candidate.entity';
import { CertificateEntity } from '../entities/certificate.entity';
import { CreateCertificateDto } from '../dto/create-certificate.dto';
import { UpdateCertificateDto } from '../dto/update-certificate.dto';

@Injectable()
export class CandidateCertificatesService {
  private readonly logger = new Logger(CandidateCertificatesService.name);

  constructor(
    @InjectRepository(CandidateEntity)
    private readonly candidateRepository: Repository<CandidateEntity>,
    @InjectRepository(CertificateEntity)
    private readonly certificateRepository: Repository<CertificateEntity>,
    private readonly supabaseService: SupabaseService,
  ) {}

  async getCertificates(userId: number) {
    const candidate = await this.findCandidateByUserId(userId);
    return this.certificateRepository.find({
      where: { candidateId: candidate.id },
    });
  }

  async createCertificate(
    userId: number,
    dto: CreateCertificateDto,
    file?: Express.Multer.File,
  ) {
    const candidate = await this.findCandidateByUserId(userId);
    let cerImgUrl: string | undefined = undefined;
    let filePath: string | undefined = undefined;

    if (file) {
      const uniqueId = Date.now();
      filePath = `candidates/${userId}/certificates/cert_${uniqueId}_${file.originalname}`;
      cerImgUrl = await this.supabaseService.uploadFile(file, filePath);
    }

    try {
      const certificate = this.certificateRepository.create({
        ...dto,
        candidateId: candidate.id,
        ...(cerImgUrl ? { cerImgUrl } : {}),
      });

      return await this.certificateRepository.save(certificate);
    } catch (e) {
      if (filePath) {
        this.logger.error(
          `Database error, deleting orphaned certificate: ${filePath}`,
        );
        await this.supabaseService.deleteFile(filePath).catch(() => null);
      }
      throw e;
    }
  }

  async updateCertificate(
    userId: number,
    certId: number,
    dto: UpdateCertificateDto,
    file?: Express.Multer.File,
  ) {
    const candidate = await this.findCandidateByUserId(userId);
    const cert = await this.certificateRepository.findOne({
      where: { id: certId },
    });

    if (!cert) throw new NotFoundException('Certificate not found');
    if (cert.candidateId !== candidate.id)
      throw new ForbiddenException(
        'You do not have permission to update this certificate',
      );

    let newImgUrl: string | undefined = undefined;
    let newFilePath: string | undefined = undefined;
    const oldImgUrl = cert.cerImgUrl;

    if (file) {
      const uniqueId = Date.now();
      newFilePath = `candidates/${userId}/certificates/cert_${uniqueId}_${file.originalname}`;
      newImgUrl = await this.supabaseService.uploadFile(file, newFilePath);
    }

    try {
      if (newImgUrl) cert.cerImgUrl = newImgUrl;
      Object.assign(cert, dto);
      await this.certificateRepository.save(cert);

      // Save was successful. Delete the old file to save space if we uploaded a new one.
      if (newImgUrl && oldImgUrl) {
        const urlParts = oldImgUrl.split('/');
        const fileName = urlParts[urlParts.length - 1];
        await this.supabaseService
          .deleteFile(`candidates/${userId}/certificates/${fileName}`)
          .catch(() => null);
      }
      return cert;
    } catch (e) {
      if (newFilePath) {
        this.logger.error(
          `Database error, deleting orphaned new certificate: ${newFilePath}`,
        );
        await this.supabaseService.deleteFile(newFilePath).catch(() => null);
      }
      throw e;
    }
  }

  async deleteCertificate(userId: number, certId: number) {
    const candidate = await this.findCandidateByUserId(userId);
    const cert = await this.certificateRepository.findOne({
      where: { id: certId },
    });

    if (!cert) throw new NotFoundException('Certificate not found');
    if (cert.candidateId !== candidate.id)
      throw new ForbiddenException(
        'You do not have permission to delete this certificate',
      );

    if (cert.cerImgUrl) {
      try {
        const urlParts = cert.cerImgUrl.split('/');
        const fileName = urlParts[urlParts.length - 1];
        await this.supabaseService.deleteFile(
          `candidates/${userId}/certificates/${fileName}`,
        );
      } catch (e) {
        this.logger.error(
          `Error deleting certificate: ${(e as Error).message}`,
          (e as Error).stack,
        );
      }
    }

    await this.certificateRepository.remove(cert);
    return { message: 'Certificate deleted successfully' };
  }

  private async findCandidateByUserId(userId: number) {
    const candidate = await this.candidateRepository.findOne({
      where: { userId },
    });
    if (!candidate) {
      throw new NotFoundException('Candidate profile not found');
    }
    return candidate;
  }
}

import {
  BadRequestException,
  Injectable,
  Logger,
  NotFoundException,
} from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository } from 'typeorm';
import { ConfigService } from '@nestjs/config';
import { GoogleGenerativeAI } from '@google/generative-ai';
import { CandidateEntity } from '../entities/candidate.entity';
import { CandidateSkillTagEntity } from '../entities/candidate-skill-tag.entity';
import { WorkExperienceEntity } from '../entities/work-experience.entity';
import { EducationEntity } from '../entities/education.entity';
import { ProjectEntity } from '../entities/project.entity';
import { CertificateEntity } from '../entities/certificate.entity';
import { SkillsMetadataService } from '../../metadata/skills/skills-metadata.service';
import { CvFullParseResult } from '../interfaces/cv-full-parse.interface';
import { ParsedEducation } from '../interfaces/parsed-education.interface';
import { ParsedProject } from '../interfaces/parsed-project.interface';
import { ParsedWorkExperience } from '../interfaces/parsed-work-experience.interface';
import { CV_FULL_PARSE_PROMPT } from '../prompts/cv-full-parse.prompt';
import { toSlug } from '../../common/utils/string.util';

// ─── Service ─────────────────────────────────────────────────────────────────

@Injectable()
export class CandidateCvParserService {
  private readonly logger = new Logger(CandidateCvParserService.name);
  private genAI: GoogleGenerativeAI;
  private readonly aiModel: string;

  constructor(
    @InjectRepository(CandidateEntity)
    private readonly candidateRepo: Repository<CandidateEntity>,
    @InjectRepository(CandidateSkillTagEntity)
    private readonly skillTagRepo: Repository<CandidateSkillTagEntity>,
    @InjectRepository(WorkExperienceEntity)
    private readonly workExpRepo: Repository<WorkExperienceEntity>,
    @InjectRepository(EducationEntity)
    private readonly educationRepo: Repository<EducationEntity>,
    @InjectRepository(ProjectEntity)
    private readonly projectRepo: Repository<ProjectEntity>,
    @InjectRepository(CertificateEntity)
    private readonly certificateRepo: Repository<CertificateEntity>,
    private readonly skillsMetadataService: SkillsMetadataService,
    private readonly configService: ConfigService,
  ) {
    const apiKey = this.configService.get<string>('GEMINI_API_KEY');
    if (apiKey) {
      this.genAI = new GoogleGenerativeAI(apiKey);
    }
    this.aiModel = this.configService.get<string>(
      'GEMINI_MODEL',
      'gemini-2.5-flash',
    );
  }

  // ─── Public API ──────────────────────────────────────────────────────────

  /**
   * Người dùng chủ động kích hoạt để AI đọc CV và điền vào profile.
   * KHÔNG tự động chạy khi upload — chỉ chạy khi user bấm nút "Parse CV".
   *
   * Chiến lược ghi dữ liệu:
   * - Profile fields (fullName, phone, position, bio, yearWorkingExperience):
   *   GHI ĐÈ nếu AI trích xuất được (≠ null).
   * - workExperiences, educations, projects:
   *   CHỈ INSERT nếu bảng chưa có bản ghi nào → tránh xóa data user đã nhập tay.
   * - certificates: THÊM MỚI theo tên, bỏ qua nếu đã có.
   * - skills: THÊM MỚI, không bao giờ xóa skill cũ.
   */
  async parseAndApply(userId: number): Promise<{
    message: string;
    summary: {
      profileFieldsUpdated: string[];
      workExperiencesAdded: number;
      educationsAdded: number;
      projectsAdded: number;
      certificatesAdded: number;
      skillsAdded: number;
    };
  }> {
    if (!this.genAI) {
      throw new BadRequestException(
        'Tính năng AI Parse CV chưa được cấu hình. Vui lòng liên hệ quản trị viên.',
      );
    }

    const candidate = await this.candidateRepo.findOne({ where: { userId } });
    if (!candidate) {
      throw new NotFoundException('Hồ sơ ứng viên không tồn tại');
    }
    if (!candidate.cvUrl) {
      throw new BadRequestException(
        'Bạn chưa upload CV. Vui lòng upload CV trước khi sử dụng tính năng này.',
      );
    }

    const fileData = await this.fetchBase64Cv(candidate.cvUrl);
    if (!fileData) {
      throw new BadRequestException(
        'Không thể đọc file CV. Đảm bảo file là PDF hoặc ảnh (JPG/PNG) dưới 10MB và thử lại.',
      );
    }

    const parsed = await this.callGeminiFullParse(fileData);

    // ── Profile fields ──
    const profileFieldsUpdated: string[] = [];
    const updates: Partial<CandidateEntity> = {};

    if (parsed.fullName) {
      updates.fullName = parsed.fullName;
      profileFieldsUpdated.push('fullName');
    }
    if (parsed.phone) {
      updates.phone = parsed.phone;
      profileFieldsUpdated.push('phone');
    }
    if (parsed.position) {
      updates.position = parsed.position;
      profileFieldsUpdated.push('position');
    }
    if (parsed.bio) {
      updates.bio = parsed.bio;
      profileFieldsUpdated.push('bio');
    }
    if (parsed.yearWorkingExperience != null) {
      updates.yearWorkingExperience = parsed.yearWorkingExperience;
      profileFieldsUpdated.push('yearWorkingExperience');
    }

    if (Object.keys(updates).length > 0) {
      Object.assign(candidate, updates);
      await this.candidateRepo.save(candidate);
    }

    // ── Related entities ──
    const [
      workExperiencesAdded,
      educationsAdded,
      projectsAdded,
      certificatesAdded,
      skillsAdded,
    ] = await Promise.all([
      this.upsertWorkExperiences(candidate.id, parsed.workExperiences),
      this.upsertEducations(candidate.id, parsed.educations),
      this.upsertProjects(candidate.id, parsed.projects),
      this.upsertCertificates(candidate.id, parsed.certificates),
      this.upsertSkills(candidate.id, parsed.skills),
    ]);

    this.logger.log(
      `CV Parse OK · Candidate #${candidate.id} · ` +
        `profile(${profileFieldsUpdated.join(',')}) · ` +
        `workExp+${workExperiencesAdded} edu+${educationsAdded} ` +
        `proj+${projectsAdded} cert+${certificatesAdded} skill+${skillsAdded}`,
    );

    return {
      message:
        `Phân tích CV thành công. Đã cập nhật ${profileFieldsUpdated.length} trường hồ sơ, ` +
        `thêm ${workExperiencesAdded} kinh nghiệm, ${educationsAdded} học vấn, ` +
        `${projectsAdded} dự án, ${certificatesAdded} chứng chỉ, ${skillsAdded} kỹ năng.`,
      summary: {
        profileFieldsUpdated,
        workExperiencesAdded,
        educationsAdded,
        projectsAdded,
        certificatesAdded,
        skillsAdded,
      },
    };
  }

  // ─── Gemini Call ─────────────────────────────────────────────────────────

  private async callGeminiFullParse(fileData: {
    base64: string;
    mimeType: string;
  }): Promise<CvFullParseResult> {
    try {
      const model = this.genAI.getGenerativeModel({ model: this.aiModel });
      const result = await model.generateContent([
        { inlineData: { data: fileData.base64, mimeType: fileData.mimeType } },
        CV_FULL_PARSE_PROMPT,
      ]);

      const text = result.response.text().trim();
      const jsonMatch = text.match(/\{[\s\S]*\}/);
      if (!jsonMatch) throw new Error('No JSON found in AI response');

      const raw = JSON.parse(jsonMatch[0]) as Partial<CvFullParseResult>;

      // Sanitize to ensure contract is met regardless of model variation
      return {
        fullName:
          typeof raw.fullName === 'string' ? raw.fullName.trim() || null : null,
        phone: typeof raw.phone === 'string' ? raw.phone.trim() || null : null,
        position:
          typeof raw.position === 'string' ? raw.position.trim() || null : null,
        bio: typeof raw.bio === 'string' ? raw.bio.trim() || null : null,
        yearWorkingExperience:
          typeof raw.yearWorkingExperience === 'number'
            ? Math.max(0, Math.round(raw.yearWorkingExperience))
            : null,
        workExperiences: Array.isArray(raw.workExperiences)
          ? raw.workExperiences.filter((w) => w?.companyName && w?.position)
          : [],
        educations: Array.isArray(raw.educations)
          ? raw.educations.filter((e) => e?.schoolName)
          : [],
        projects: Array.isArray(raw.projects)
          ? raw.projects.filter((p) => p?.name)
          : [],
        certificates: Array.isArray(raw.certificates)
          ? raw.certificates.filter((c) => typeof c === 'string' && c.trim())
          : [],
        skills: Array.isArray(raw.skills)
          ? raw.skills.filter((s) => typeof s === 'string' && s.trim())
          : [],
      };
    } catch (error: unknown) {
      this.logger.error(
        'Gemini CV parse failed',
        error instanceof Error ? error.message : String(error),
      );
      throw new BadRequestException(
        'AI không thể phân tích nội dung CV. Vui lòng thử lại hoặc điền thông tin thủ công.',
      );
    }
  }

  // ─── Upsert: Work Experiences ─────────────────────────────────────────────

  private async upsertWorkExperiences(
    candidateId: number,
    items: ParsedWorkExperience[],
  ): Promise<number> {
    if (!items.length) return 0;
    const count = await this.workExpRepo.count({ where: { candidateId } });
    if (count > 0) return 0; // User đã tự quản lý, không ghi đè

    const entities = items.map((w) =>
      this.workExpRepo.create({
        candidateId,
        companyName: w.companyName,
        position: w.position,
        startDate: w.startDate ?? undefined,
        endDate: w.isWorkingHere ? undefined : (w.endDate ?? undefined),
        isWorkingHere: w.isWorkingHere ?? false,
        description: w.description ?? undefined,
      }),
    );
    await this.workExpRepo.save(entities);
    return entities.length;
  }

  // ─── Upsert: Educations ───────────────────────────────────────────────────

  private async upsertEducations(
    candidateId: number,
    items: ParsedEducation[],
  ): Promise<number> {
    if (!items.length) return 0;
    const count = await this.educationRepo.count({ where: { candidateId } });
    if (count > 0) return 0;

    const entities = items.map((e) =>
      this.educationRepo.create({
        candidateId,
        schoolName: e.schoolName,
        major: e.major ?? undefined,
        degree: e.degree ?? undefined,
        startDate: e.startDate ?? undefined,
        endDate: e.isStillStudying ? undefined : (e.endDate ?? undefined),
        isStillStudying: e.isStillStudying ?? false,
        description: e.description ?? undefined,
      }),
    );
    await this.educationRepo.save(entities);
    return entities.length;
  }

  // ─── Upsert: Projects ─────────────────────────────────────────────────────

  private async upsertProjects(
    candidateId: number,
    items: ParsedProject[],
  ): Promise<number> {
    if (!items.length) return 0;
    const count = await this.projectRepo.count({ where: { candidateId } });
    if (count > 0) return 0;

    const entities = items.map((p) =>
      this.projectRepo.create({
        candidateId,
        name: p.name,
        startDate: p.startDate ?? undefined,
        endDate: p.endDate ?? undefined,
        description: p.description ?? undefined,
      }),
    );
    await this.projectRepo.save(entities);
    return entities.length;
  }

  // ─── Upsert: Certificates ─────────────────────────────────────────────────

  private async upsertCertificates(
    candidateId: number,
    names: string[],
  ): Promise<number> {
    if (!names.length) return 0;

    const existing = await this.certificateRepo.find({
      where: { candidateId },
    });
    const existingSet = new Set(existing.map((c) => c.name.toLowerCase()));

    const newOnes = names
      .map((n) => n.trim())
      .filter((n) => n && !existingSet.has(n.toLowerCase()))
      .map((name) => this.certificateRepo.create({ candidateId, name }));

    if (newOnes.length > 0) await this.certificateRepo.save(newOnes);
    return newOnes.length;
  }

  // ─── Upsert: Skills ───────────────────────────────────────────────────────

  /**
   * Pipeline chuẩn hoá kỹ năng:
   *   1. Fuzzy-match với skill_metadata → nếu tìm thấy, upsert tag.
   *   2. Không tìm thấy → gọi AI formatter (SKILL_STANDARDIZER_PROMPT) → upsert skill mới → upsert tag.
   * Chạy tuần tự để tránh race condition khi insert vào skill_metadata.
   * CHỈ THÊM, không bao giờ xóa skill cũ.
   */
  private async upsertSkills(
    candidateId: number,
    skillNames: string[],
  ): Promise<number> {
    if (!skillNames.length) return 0;

    const uniqueRawSkills = Array.from(
      new Set(skillNames.map((s) => s.trim()).filter((s) => s)),
    );
    // 1. Phân loại kỹ năng đã có trong hệ thống và lạ (Sử dụng BATCH lookup)
    const foundSkills =
      await this.skillsMetadataService.findManyByFuzzy(uniqueRawSkills);

    const foundSkillSlugs = new Set(foundSkills.map((s) => s.slug));
    const knownSkillsList = [...foundSkills];
    const unknownRawSkillsList = uniqueRawSkills.filter(
      (raw) => !foundSkillSlugs.has(toSlug(raw)),
    );

    // 2. Gom tất cả kỹ năng lạ gọi AI 1 LẦN DUY NHẤT để khỏi dính Too Many Requests
    if (unknownRawSkillsList.length > 0) {
      try {
        const formatted =
          await this.skillsMetadataService.formatWithAI(unknownRawSkillsList);
        for (let i = 0; i < formatted.length; i++) {
          const raw = unknownRawSkillsList[i] || formatted[i].name;
          const { name, type } = formatted[i];
          const newSkill = await this.skillsMetadataService.upsertSkill(
            name,
            type,
            raw,
          );
          knownSkillsList.push(newSkill);
        }
      } catch (err: unknown) {
        this.logger.error('Failed to batch format skills with AI', err);
      }
    }

    // 3. Gắn tag cho ứng viên
    let added = 0;
    for (const skill of knownSkillsList) {
      if (!skill) continue;
      const existing = await this.skillTagRepo.findOne({
        where: { candidateId, skillMetadataId: skill.id },
      });
      if (!existing) {
        await this.skillTagRepo.save(
          this.skillTagRepo.create({ candidateId, skillMetadataId: skill.id }),
        );
        await this.skillsMetadataService.incrementUseCount(skill.id);
        added++;
      }
    }

    return added;
  }

  // ─── Fetch CV as Base64 ───────────────────────────────────────────────────

  private async fetchBase64Cv(
    url: string | null,
  ): Promise<{ base64: string; mimeType: string } | null> {
    if (!url || !url.startsWith('http')) return null;

    // --- SSRF Protection Start ---
    const supabaseUrl = this.configService.get<string>('SUPABASE_PROJECT_URL');
    if (supabaseUrl) {
      try {
        const urlHost = new URL(url).host;
        const supabaseHost = new URL(supabaseUrl).host;
        if (urlHost !== supabaseHost) {
          this.logger.warn(
            `SSRF Blocked: URL host ${urlHost} does not match ${supabaseHost}`,
          );
          return null;
        }
      } catch {
        return null;
      }
    }
    // --- SSRF Protection End ---

    try {
      const res = await fetch(url);
      if (!res.ok) return null;

      const contentLength = res.headers.get('content-length');
      if (contentLength && parseInt(contentLength, 10) > 10 * 1024 * 1024) {
        this.logger.warn(`CV too large (${contentLength} bytes): ${url}`);
        return null;
      }

      const mimeType = res.headers.get('content-type') || 'application/pdf';
      if (!mimeType.includes('pdf') && !mimeType.includes('image')) return null;

      const buffer = Buffer.from(await res.arrayBuffer());
      return { base64: buffer.toString('base64'), mimeType };
    } catch (e: unknown) {
      this.logger.error('Fetch CV failed: ' + url, e);
      return null;
    }
  }
}

import {
  Injectable,
