@Injectable()
export class CompaniesService {
  private readonly logger = new Logger(CompaniesService.name);
  constructor(
    @InjectRepository(CompanyEntity)
    private readonly companyRepo: Repository<CompanyEntity>,
    @InjectRepository(CompanyImageEntity)
    private readonly companyImageRepo: Repository<CompanyImageEntity>,
    @InjectRepository(CompanyStatusHistoryEntity)
    private readonly historyRepo: Repository<CompanyStatusHistoryEntity>,
    private readonly supabaseService: SupabaseService,
  ) {}

  async getCompanyPublicBySlug(slug: string) {
    const company = await this.companyRepo.findOne({
      where: { slug },
      relations: ['images'],
    });

    if (!company) {
      throw new NotFoundException('Không tìm thấy thông tin công ty');
    }

    // Chỉ trả về các trường công khai cho ứng viên
    return {
      id: company.id,
      name: company.name,
      emailContact: company.emailContact,
      phoneContact: company.phoneContact,
      address: company.address,
      provinceId: company.provinceId,
      logoUrl: company.logoUrl,
      bannerUrl: company.bannerUrl,
      description: company.description,
      content: company.content,
      companySize: company.companySize,
      websiteUrl: company.websiteUrl,
      facebookUrl: company.facebookUrl,
      linkedinUrl: company.linkedinUrl,
      createdAt: company.createdAt,
      updatedAt: company.updatedAt,
      slug: company.slug,
      images: company.images,
    };
  }

  /**
   * Helper function to find company verifying userCreatorId
   */
  async getCompanyByUser(userId: number) {
    const company = await this.companyRepo.findOne({
      where: { userCreatorId: userId },
      relations: ['images', 'employers'],
    });

    if (!company) {
      throw new NotFoundException(
        'Không tìm thấy công ty của tài khoản này hoặc bạn không phải admin',
      );
    }

    return company;
  }

  async updateCompanyProfile(userId: number, dto: UpdateCompanyDto) {
    const company = await this.getCompanyByUser(userId);

    Object.assign(company, dto);

    if (dto.name) {
      company.slug = toSlug(dto.name);
    }

    await this.companyRepo.save(company);
    return company;
  }

  async uploadLogo(userId: number, file: Express.Multer.File) {
    if (!file) throw new BadRequestException('Vui lòng chọn file logo');
    const company = await this.getCompanyByUser(userId);

    const originalName = sanitizeFilename(file.originalname);
    const filePath = `${STORAGE_PATHS.COMPANIES.LOGOS}/${company.id}-${Date.now()}-${originalName}`;
    const oldFilePath = company.logoUrl
      ? `${STORAGE_PATHS.COMPANIES.LOGOS}/${company.logoUrl.split('/').pop()}`
      : undefined;

    const { result } = await this.supabaseService.atomicUploadAndUpdate(
      file,
      filePath,
      async (url) => {
        company.logoUrl = url;
        await this.companyRepo.save(company);
        return { message: 'Upload logo thành công', logoUrl: url };
      },
      oldFilePath,
    );

    return result;
  }

  async uploadBanner(userId: number, file: Express.Multer.File) {
    if (!file) throw new BadRequestException('Vui lòng chọn file banner');
    const company = await this.getCompanyByUser(userId);

    const originalName = sanitizeFilename(file.originalname);
    const filePath = `${STORAGE_PATHS.COMPANIES.BANNERS}/${company.id}-${Date.now()}-${originalName}`;
    const oldFilePath = company.bannerUrl
      ? `${STORAGE_PATHS.COMPANIES.BANNERS}/${company.bannerUrl.split('/').pop()}`
      : undefined;

    const { result } = await this.supabaseService.atomicUploadAndUpdate(
      file,
      filePath,
      async (url) => {
        company.bannerUrl = url;
        await this.companyRepo.save(company);
        return { message: 'Upload banner thành công', bannerUrl: url };
      },
      oldFilePath,
    );

    return result;
  }

  async uploadCompanyImages(userId: number, files: Express.Multer.File[]) {
    if (!files || files.length === 0) {
      throw new BadRequestException('Vui lòng chọn ít nhất 1 hình ảnh');
    }
    const company = await this.getCompanyByUser(userId);

    const uploadedImages = [];
    // Track all uploaded paths for orphan cleanup if a DB save fails mid-batch
    const uploadedPaths: string[] = [];

    for (const file of files) {
      const originalName = sanitizeFilename(file.originalname);
      const filePath = `${STORAGE_PATHS.COMPANIES.IMAGES}/${company.id}-${Date.now()}-${originalName}`;
      const imageUrl = await this.supabaseService.uploadFile(file, filePath);
      uploadedPaths.push(filePath);

      try {
        const newImage = this.companyImageRepo.create({
          companyId: company.id,
          imageUrl,
        });
        const savedImage = await this.companyImageRepo.save(newImage);
        uploadedImages.push(savedImage);
      } catch (dbError) {
        // Orphan Fix: DB failed → delete ALL files uploaded in this batch
        this.logger.error(
          `Failed to save image record, deleting ${uploadedPaths.length} orphaned file(s)...`,
        );
        await Promise.all(
          uploadedPaths.map((p) =>
            this.supabaseService.deleteFile(p).catch(() => null),
          ),
        );
        throw dbError;
      }
    }

    return {
      message: 'Upload hình ảnh môi trường làm việc thành công',
      images: uploadedImages,
    };
  }

  async deleteCompanyImage(userId: number, imageId: number) {
    const company = await this.getCompanyByUser(userId);

    const image = await this.companyImageRepo.findOne({
      where: { id: imageId, companyId: company.id },
    });

    if (!image) {
      throw new NotFoundException(
        'Hình ảnh không tồn tại hoặc không có quyền xóa',
      );
    }

    await this.companyImageRepo.remove(image);
    return { message: 'Xóa hình ảnh thành công' };
  }

  // -----------------------
  // BUSINESS LICENSE & VERIFICATION
  // -----------------------

  async uploadBusinessLicense(userId: number, file: Express.Multer.File) {
    if (!file) {
      throw new BadRequestException('Vui lòng chọn file giấy phép kinh doanh');
    }
    const company = await this.getCompanyByUser(userId);

    const originalName = sanitizeFilename(file.originalname);
    const filePath = `${STORAGE_PATHS.COMPANIES.LICENSES}/${company.id}-${Date.now()}-${originalName}`;
    const oldFilePath = company.businessLicenseUrl
      ? `${STORAGE_PATHS.COMPANIES.LICENSES}/${company.businessLicenseUrl.split('/').pop()}`
      : undefined;

    const { result } = await this.supabaseService.atomicUploadAndUpdate(
      file,
      filePath,
      async (url) => {
        company.businessLicenseUrl = url;
        company.status = CompanyStatus.PENDING;
        await this.companyRepo.save(company);
        return {
          message:
            'Tải lên giấy phép kinh doanh thành công. Vui lòng chờ Admin duyệt.',
          licenseUrl: url,
        };
      },
      oldFilePath,
    );

    return result;
  }

  async getPendingVerifications(page = 1, limit = 10) {
    const skip = (page - 1) * limit;

    const qb = this.companyRepo
      .createQueryBuilder('company')
      .where('company.businessLicenseUrl IS NOT NULL')
      .andWhere('company.status = :status', { status: CompanyStatus.PENDING });

    qb.orderBy('company.updatedAt', 'DESC').skip(skip).take(limit);

    const [data, total] = await qb.getManyAndCount();

    return {
      data,
      total,
      page,
      lastPage: Math.ceil(total / limit),
    };
  }

  async verifyCompany(id: number) {
    const company = await this.companyRepo.findOne({ where: { id } });
    if (!company) throw new NotFoundException('Không tìm thấy công ty');

    const oldStatus = company.status;
    await this.companyRepo.update(id, {
      status: CompanyStatus.APPROVED,
      verifiedAt: new Date(),
      rejectionReason: null,
    });

    // Log history
    await this.historyRepo.save(
      this.historyRepo.create({
        companyId: id,
        oldStatus,
        newStatus: CompanyStatus.APPROVED,
      }),
    );

    return { message: 'Công ty đã được xác nhận thực thành công' };
  }

  async rejectVerification(id: number, reason: string) {
    const company = await this.companyRepo.findOne({ where: { id } });
    if (!company) throw new NotFoundException('Không tìm thấy công ty');

    const oldStatus = company.status;
    await this.companyRepo.update(id, {
      status: CompanyStatus.REJECTED,
      rejectionReason: reason,
    });

    // Log history
    await this.historyRepo.save(
      this.historyRepo.create({
        companyId: id,
        oldStatus,
        newStatus: CompanyStatus.REJECTED,
        reason,
      }),
    );

    return { message: `Đã từ chối xác thực. Lý do: ${reason}` };
  }

  async getCompanyHistory(companyId: number) {
    return this.historyRepo.find({
      where: { companyId },
      order: { createdAt: 'DESC' },
    });
  }
}

import {
  Injectable,
  NotFoundException,
  BadRequestException,
  ForbiddenException,
  Logger,
} from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { DataSource, Repository } from 'typeorm';
import {
  JobApplicationEntity,
  ApplicationStatus,
} from './entities/job-application.entity';
import { ApplicationStatusHistoryEntity } from './entities/application-status-history.entity';
import { JobEntity } from '../jobs/entities/job.entity';
import { EmployerEntity } from '../employers/entities/employer.entity';
import { ApplicationFilterDto } from './dto/application-filter.dto';
import { UpdateApplicationStatusDto } from './dto/update-application-status.dto';
import { ApplicationNoteEntity } from './entities/application-note.entity';
import { CreateApplicationNoteDto } from './dto/create-application-note.dto';
import { UpdateApplicationNoteDto } from './dto/update-application-note.dto';

@Injectable()
export class EmployerApplicationsService {
  private readonly logger = new Logger(EmployerApplicationsService.name);

  constructor(
    @InjectRepository(JobApplicationEntity)
    private readonly applicationRepo: Repository<JobApplicationEntity>,
    @InjectRepository(ApplicationStatusHistoryEntity)
    private readonly historyRepo: Repository<ApplicationStatusHistoryEntity>,
    @InjectRepository(JobEntity)
    private readonly jobRepo: Repository<JobEntity>,
    @InjectRepository(EmployerEntity)
    private readonly employerRepo: Repository<EmployerEntity>,
    @InjectRepository(ApplicationNoteEntity)
    private readonly noteRepo: Repository<ApplicationNoteEntity>,
    private readonly dataSource: DataSource,
  ) {}

  async getJobApplications(
    employerUserId: number,
    jobId: number,
    filterDto: ApplicationFilterDto,
  ) {
    const employer = await this.findEmployerByUserId(employerUserId);

    const job = await this.jobRepo.findOne({
      where: { id: jobId, companyId: employer.companyId },
    });
    if (!job) {
      throw new NotFoundException(
        'Tin tuyển dụng không tồn tại hoặc không thuộc công ty của bạn',
      );
    }

    const { page = 1, limit = 10, status } = filterDto;

    const qb = this.applicationRepo
      .createQueryBuilder('app')
      .leftJoinAndSelect('app.candidate', 'candidate')
      .leftJoinAndSelect('candidate.skills', 'skills')
      .leftJoinAndSelect('skills.skillMetadata', 'skillMetadata')
      .where('app.jobId = :jobId', { jobId });

    if (status) {
      qb.andWhere('app.status = :status', { status });
    }

    qb.orderBy('app.appliedAt', 'DESC');

    const skip = (page - 1) * limit;
    const [data, total] = await qb.skip(skip).take(limit).getManyAndCount();

    return { data, total, page, lastPage: Math.ceil(total / limit) };
  }

  async getKanbanBoard(employerUserId: number, jobId: number) {
    const employer = await this.findEmployerByUserId(employerUserId);

    const job = await this.jobRepo.findOne({
      where: { id: jobId, companyId: employer.companyId },
    });
    if (!job) {
      throw new NotFoundException(
        'Tin tuyển dụng không tồn tại hoặc không thuộc công ty của bạn',
      );
    }

    const columns = [
      { id: ApplicationStatus.APPLIED, title: 'Mới ứng tuyển' },
      { id: ApplicationStatus.SHORTLISTED, title: 'Tiềm năng' },
      { id: ApplicationStatus.SKILL_TEST, title: 'Skill Test' },
      { id: ApplicationStatus.INTERVIEW, title: 'Phỏng vấn' },
      { id: ApplicationStatus.OFFER, title: 'Gửi đề nghị' },
      { id: ApplicationStatus.HIRED, title: 'Đã tuyển' },
      { id: ApplicationStatus.REJECTED, title: 'Đã từ chối' },
      { id: ApplicationStatus.WITHDRAWN, title: 'Đã rút đơn' },
    ];

    // 1. Tính tổng số lượng ở mỗi cột
    const counts = await this.applicationRepo
      .createQueryBuilder('app')
      .select('app.status', 'status')
      .addSelect('COUNT(*)::int', 'count')
      .where('app.jobId = :jobId', { jobId })
      .groupBy('app.status')
      .getRawMany<{ status: string; count: number }>();

    const countMap = new Map<string, number>();
    for (const row of counts) {
      countMap.set(row.status, row.count);
    }

    // 2. Chạy 8 query song song để lấy 10 item mới nhất cho mỗi cột (tránh N+1 và load vào RAM)
    const columnPromises = columns.map(async (col) => {
      const items = await this.applicationRepo.find({
        where: { jobId, status: col.id },
        relations: [
          'candidate',
          'candidate.skills',
          'candidate.skills.skillMetadata',
        ],
        order: { appliedAt: 'DESC' },
        take: 10,
      });

      return {
        id: col.id,
        title: col.title,
        count: countMap.get(col.id) || 0,
        items,
      };
    });

    return Promise.all(columnPromises);
  }

  async getApplicationDetail(employerUserId: number, applicationId: number) {
    const employer = await this.findEmployerByUserId(employerUserId);

    const application = await this.applicationRepo.findOne({
      where: {
        id: applicationId,
        job: { companyId: employer.companyId }, // Early Check Authorization
      },
      relations: [
        'job',
        'candidate',
        'candidate.skills',
        'candidate.skills.skillMetadata',
        'candidate.workExperiences',
        'candidate.projects',
        'candidate.certificates',
        'statusHistory',
        'notes',
        'notes.author',
        'notes.author.employer',
      ],
      order: {
        notes: { createdAt: 'DESC' },
      },
    });

    if (!application) {
      throw new NotFoundException(
        'Đơn ứng tuyển không tồn tại hoặc bạn không có quyền truy cập',
      );
    }

    return application;
  }

  async updateApplicationStatus(
    employerUserId: number,
    applicationId: number,
    dto: UpdateApplicationStatusDto,
  ) {
    const employer = await this.findEmployerByUserId(employerUserId);

    const application = await this.applicationRepo.findOne({
      where: {
        id: applicationId,
        job: { companyId: employer.companyId },
      },
      relations: ['job'],
    });

    if (!application) {
      throw new NotFoundException(
        'Đơn ứng tuyển không tồn tại hoặc bạn không có quyền truy cập',
      );
    }

    if (application.status === (ApplicationStatus.WITHDRAWN as string)) {
      throw new BadRequestException(
        'Không thể thay đổi trạng thái đơn đã được ứng viên rút',
      );
    }

    if (application.status === (ApplicationStatus.REJECTED as string)) {
      throw new BadRequestException(
        'Không thể thay đổi trạng thái đơn đã bị từ chối. Hãy tạo đơn mới nếu cần.',
      );
    }

    const employerForbiddenStatuses: string[] = [
      ApplicationStatus.APPLIED,
      ApplicationStatus.WITHDRAWN,
    ];
    if (employerForbiddenStatuses.includes(dto.status)) {
      throw new BadRequestException(
        `Nhà tuyển dụng không được phép chuyển sang trạng thái "${dto.status}"`,
      );
    }

    if (dto.status === ApplicationStatus.REJECTED && !dto.reason) {
      throw new BadRequestException(
        'Vui lòng cung cấp lý do khi từ chối ứng viên',
      );
    }

    const oldStatus = application.status;
    application.status = dto.status;

    if (dto.status === ApplicationStatus.REJECTED) {
      application.rejectionReason = dto.reason ?? null;
    }

    if (dto.note !== undefined && dto.note !== null && dto.note.trim() !== '') {
      // Logic mới: Tự động tạo note record thay vì ghi đè record cũ
      application.employerNote = `[Sytem] Trạng thái thay đổi sang ${dto.status}. Note cũ được lưu vào timeline.`;
    }

    await this.dataSource.transaction(async (manager) => {
      await manager.save(JobApplicationEntity, application);
      await manager.save(
        ApplicationStatusHistoryEntity,
        manager.create(ApplicationStatusHistoryEntity, {
          applicationId,
          oldStatus,
          newStatus: dto.status,
          reason: dto.reason ?? null,
          changedById: employerUserId,
        }),
      );
      if (dto.note) {
        await manager.save(
          ApplicationNoteEntity,
          manager.create(ApplicationNoteEntity, {
            applicationId,
            authorId: employerUserId,
            content: dto.note,
          }),
        );
      }
    });

    return {
      message: `Đã cập nhật trạng thái thành "${dto.status}"`,
    };
  }

  async getApplicationHistory(employerUserId: number, applicationId: number) {
    const employer = await this.findEmployerByUserId(employerUserId);

    const application = await this.applicationRepo.findOne({
      where: {
        id: applicationId,
        job: { companyId: employer.companyId },
      },
      relations: ['job'],
    });

    if (!application) {
      throw new NotFoundException(
        'Đơn ứng tuyển không tồn tại hoặc bạn không có quyền truy cập',
      );
    }

    return this.historyRepo.find({
      where: { applicationId },
      order: { createdAt: 'DESC' },
    });
  }

  async addNote(
    employerUserId: number,
    applicationId: number,
    dto: CreateApplicationNoteDto,
  ) {
    const employer = await this.findEmployerByUserId(employerUserId);

    const application = await this.applicationRepo.findOne({
      where: {
        id: applicationId,
        job: { companyId: employer.companyId },
      },
      relations: ['job'],
    });

    if (!application) {
      throw new NotFoundException(
        'Đơn ứng tuyển không tồn tại hoặc bạn không có quyền truy cập',
      );
    }

    const note = this.noteRepo.create({
      applicationId,
      authorId: employerUserId,
      content: dto.content,
    });

    return this.noteRepo.save(note);
  }

  async updateNote(
    employerUserId: number,
    noteId: number,
    dto: UpdateApplicationNoteDto,
  ) {
    const employer = await this.findEmployerByUserId(employerUserId);

    const note = await this.noteRepo.findOne({
      where: { id: noteId },
      relations: ['application', 'application.job'],
    });

    if (!note) {
      throw new NotFoundException('Không tìm thấy ghi chú');
    }

    // Kiểm tra quyền: Chỉ người tạo và thuộc cùng công ty mới được sửa
    if (note.authorId !== employerUserId) {
      throw new ForbiddenException(
        'Bạn không có quyền sửa ghi chú của người khác',
      );
    }

    if (note.application.job.companyId !== employer.companyId) {
      throw new ForbiddenException('Ghi chú không thuộc công ty của bạn');
    }

    note.content = dto.content;
    return this.noteRepo.save(note);
  }

  private async findEmployerByUserId(userId: number) {
    const employer = await this.employerRepo.findOne({
      where: { userId },
    });
    if (!employer) {
      throw new ForbiddenException('Tài khoản không phải nhà tuyển dụng');
    }
    if (!employer.companyId) {
      throw new ForbiddenException(
        'Bạn phải tham gia vào một công ty trước khi quản lý ứng tuyển',
      );
    }
    return employer;
  }
}

import {
  Injectable,
  NotFoundException,
  ForbiddenException,
  BadRequestException,
  Logger,
} from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository, In } from 'typeorm';
import { CandidateEntity } from '../candidates/entities/candidate.entity';
import { CertificateEntity } from '../candidates/entities/certificate.entity';
import { SavedCandidateEntity } from './entities/saved-candidate.entity';
import { EmployerEntity } from './entities/employer.entity';
import { JobEntity, JobStatus } from '../jobs/entities/job.entity';
import {
  JobInvitationEntity,
  InvitationStatus,
} from '../jobs/entities/job-invitation.entity';
import { HeadhuntingFilterDto } from './dto/headhunting-filter.dto';
import { SaveCandidateDto } from './dto/save-candidate.dto';
import { CreateJobInvitationDto } from '../jobs/dto/create-job-invitation.dto';

@Injectable()
export class EmployerHeadhuntingService {
  private readonly logger = new Logger(EmployerHeadhuntingService.name);

  constructor(
    @InjectRepository(CandidateEntity)
    private readonly candidateRepo: Repository<CandidateEntity>,
    @InjectRepository(CertificateEntity)
    private readonly certificateRepo: Repository<CertificateEntity>,
    @InjectRepository(SavedCandidateEntity)
    private readonly savedCandidateRepo: Repository<SavedCandidateEntity>,
    @InjectRepository(EmployerEntity)
    private readonly employerRepo: Repository<EmployerEntity>,
    @InjectRepository(JobEntity)
    private readonly jobRepo: Repository<JobEntity>,
    @InjectRepository(JobInvitationEntity)
    private readonly invitationRepo: Repository<JobInvitationEntity>,
  ) {}

  async getSuggestedCandidates(employerUserId: number, jobId: number) {
    const employer = await this.findEmployerByUserId(employerUserId);

    const job = await this.jobRepo.findOne({
      where: { id: jobId, companyId: employer.companyId },
      relations: ['skills'],
    });

    if (!job) {
      throw new NotFoundException(
        'Tin tuyển dụng không tồn tại hoặc không thuộc công ty của bạn',
      );
    }

    if (job.status !== (JobStatus.PUBLISHED as string)) {
      throw new BadRequestException(
        'Chỉ có thể gợi ý ứng viên cho tin tuyển dụng đang đăng tuyển (PUBLISHED)',
      );
    }

    // Guard: categoryId missing - log warning but keep going (fallback to skill-only)
    if (!job.categoryId) {
      this.logger.warn(
        `Job #${jobId} missing categoryId. Results will be less accurate.`,
      );
    }

    const jobSkillIds = job.skills
      .map((s) => s.skillId)
      .filter((id): id is number => id != null);

    // ----------------------------------------------------------------
    // FIX #1: Tách thành 2-step query để tránh PostgreSQL GROUP BY crash
    //   Bước 1: Raw query chỉ lấy candidate_id + scores (GROUP BY c.id OK)
    //   Bước 2: Fetch full entities theo danh sách IDs
    // ----------------------------------------------------------------
    const rawQb = this.candidateRepo.createQueryBuilder('c');

    if (job.categoryId) {
      rawQb.innerJoin('c.jobCategories', 'cjc');
    } else {
      rawQb.leftJoin('c.jobCategories', 'cjc'); // Optional if no category set
    }

    rawQb
      .leftJoin(
        'c.skills',
        'cst',
        // FIX #2: Dùng property name (skillMetadataId) thay vì raw column
        jobSkillIds.length > 0 ? 'cst.skillMetadataId IN (:...skills)' : '1=0',
        jobSkillIds.length > 0 ? { skills: jobSkillIds } : {},
      )
      // FIX #3: Chỉ select c.id để GROUP BY hoạt động đúng
      .select('c.id', 'candidateId')
      .addSelect('COUNT(DISTINCT cst.skillMetadataId)', 'matchedSkills')
      // FIX #4: Dùng Entity class trong subquery thay vì raw string
      .addSelect((sub) => {
        return sub
          .select('COUNT(cert.id)', 'cnt')
          .from(CertificateEntity, 'cert')
          .where('cert.candidateId = c.id');
      }, 'certBonus')

      // LỚP 1: LỌC CỨNG
      .where('c.isPublic = true');

    if (job.categoryId) {
      rawQb.andWhere('cjc.jobCategoryId = :jobCategoryId', {
        jobCategoryId: job.categoryId,
      });
    }

    rawQb.andWhere('COALESCE(c.yearWorkingExperience, 0) >= :minExp', {
      minExp: job.yearsOfExperience ?? 0,
    });

    // FIX #6: Guard NULL jobTypeId (không thêm điều kiện nếu job chưa set)
    if (job.jobTypeId) {
      rawQb.andWhere('c.jobTypeId = :jobTypeId', { jobTypeId: job.jobTypeId });
    }

    // FIX #7: Guard NULL provinceId
    if (job.provinceId) {
      rawQb.andWhere('(c.provinceId = :provinceId OR c.provinceId IS NULL)', {
        provinceId: job.provinceId,
      });
    }

    // FIX #8: Dùng alias đã select và hàm aggregate cho các cột không nằm trong GROUP BY
    rawQb
      .groupBy('c.id')
      .orderBy('matchedSkills', 'DESC')
      .addOrderBy('MAX(c.yearWorkingExperience)', 'DESC')
      .limit(50);

    const rawRows = await rawQb.getRawMany<{
      candidateId: string; // Raw query trả về string
      matchedSkills: string;
      certBonus: string;
    }>();

    if (rawRows.length === 0) return [];

    const orderedIds = rawRows.map((r) => Number(r.candidateId));
    const scoreMap = new Map(
      rawRows.map((r) => [
        parseInt(String(r.candidateId), 10),
        {
          matchedSkillsCount: parseInt(r.matchedSkills || '0', 10),
          certificateBonusCount: parseInt(r.certBonus || '0', 10),
        },
      ]),
    );

    // Bước 2: Fetch full entities theo IDs đã có score
    const entities = await this.candidateRepo.find({
      where: { id: In(orderedIds) },
      relations: ['skills', 'skills.skillMetadata', 'jobCategories', 'jobType'],
    });

    // Preserve thứ tự theo score
    const entityMap = new Map(entities.map((e) => [e.id, e]));
    return orderedIds
      .map((id) => {
        const entity = entityMap.get(id);
        if (!entity) return null;
        return { ...entity, ...scoreMap.get(id) };
      })
      .filter(Boolean);
  }

  async searchCandidates(employerUserId: number, filter: HeadhuntingFilterDto) {
    await this.findEmployerByUserId(employerUserId);

    const {
      keyword,
      provinceId,
      jobCategoryId,
      jobTypeId,
      minExperience,
      page,
      limit,
    } = filter;

    const qb = this.candidateRepo
      .createQueryBuilder('c')
      .leftJoinAndSelect('c.skills', 'skills')
      .leftJoinAndSelect('skills.skillMetadata', 'skillMeta')
      // FIX: Dùng property name thay vì raw column
      .where('c.isPublic = true');

    if (jobCategoryId) {
      // FIX: ON condition dùng property name để TypeORM map đúng
      qb.innerJoin('c.jobCategories', 'cjc', 'cjc.jobCategoryId = :catId', {
        catId: jobCategoryId,
      });
    }

    if (keyword) {
      // FIX: Dùng property name
      qb.andWhere(
        '(c.position ILIKE :kw OR c.bio ILIKE :kw OR c.fullName ILIKE :kw)',
        { kw: `%${keyword}%` },
      );
    }

    if (provinceId) {
      qb.andWhere('c.provinceId = :provinceId', { provinceId });
    }

    if (jobTypeId) {
      qb.andWhere('c.jobTypeId = :jobTypeId', { jobTypeId });
    }

    if (minExperience !== undefined) {
      qb.andWhere('COALESCE(c.yearWorkingExperience, 0) >= :minExp', {
        minExp: minExperience,
      });
    }

    qb.orderBy('c.yearWorkingExperience', 'DESC').addOrderBy('c.id', 'DESC');

    const skip = (page - 1) * limit;
    const [data, total] = await qb.skip(skip).take(limit).getManyAndCount();

    return { data, total, page, lastPage: Math.ceil(total / limit) };
  }

  async getCandidateDetail(employerUserId: number, candidateId: number) {
    await this.findEmployerByUserId(employerUserId);

    const candidate = await this.candidateRepo.findOne({
      where: { id: candidateId, isPublic: true },
      relations: [
        'jobType',
        'skills',
        'skills.skillMetadata',
        'workExperiences',
        'educations',
        'projects',
        'certificates',
        'jobCategories',
        'jobCategories.jobCategory',
      ],
    });

    if (!candidate) {
      throw new NotFoundException(
        'Không tìm thấy ứng viên hoặc hồ sơ không được công khai',
      );
    }

    return candidate;
  }

  async saveCandidate(
    employerUserId: number,
    candidateId: number,
    dto: SaveCandidateDto,
  ) {
    const employer = await this.findEmployerByUserId(employerUserId);

    const candidate = await this.candidateRepo.findOne({
      where: { id: candidateId, isPublic: true },
    });
    if (!candidate) {
      throw new NotFoundException('Ứng viên không tồn tại hoặc đã ẩn hồ sơ');
    }

    let saved = await this.savedCandidateRepo.findOne({
      where: { employerId: employer.id, candidateId },
    });

    if (saved) {
      saved.note = dto.note || saved.note;
    } else {
      saved = this.savedCandidateRepo.create({
        employerId: employer.id,
        candidateId,
        note: dto.note,
      });
    }

    return this.savedCandidateRepo.save(saved);
  }

  async unsaveCandidate(employerUserId: number, candidateId: number) {
    const employer = await this.findEmployerByUserId(employerUserId);
    const result = await this.savedCandidateRepo.delete({
      employerId: employer.id,
      candidateId,
    });

    if (result.affected === 0) {
      throw new NotFoundException('Ứng viên chưa được lưu trong Talent Pool');
    }

    return { message: 'Đã xóa ứng viên khỏi Talent Pool' };
  }

  async getSavedCandidates(employerUserId: number) {
    const employer = await this.findEmployerByUserId(employerUserId);

    return this.savedCandidateRepo.find({
      where: { employerId: employer.id },
      relations: [
        'candidate',
        'candidate.skills',
        'candidate.skills.skillMetadata',
        'candidate.jobCategories',
        'candidate.jobType',
      ],
      order: { createdAt: 'DESC' },
    });
  }

  async sendJobInvitation(employerUserId: number, dto: CreateJobInvitationDto) {
    const employer = await this.findEmployerByUserId(employerUserId);

    // FIX: Kiểm tra Job tồn tại + thuộc công ty + đang PUBLISHED
    const job = await this.jobRepo.findOne({
      where: { id: dto.jobId, companyId: employer.companyId },
    });
    if (!job) {
      throw new NotFoundException('Tin tuyển dụng không tồn tại');
    }
    if (job.status !== (JobStatus.PUBLISHED as string)) {
      throw new BadRequestException(
        'Chỉ có thể gửi thư mời cho tin tuyển dụng đang đăng tuyển',
      );
    }

    const candidate = await this.candidateRepo.findOne({
      where: { id: dto.candidateId, isPublic: true },
    });
    if (!candidate) {
      throw new NotFoundException('Ứng viên không tồn tại hoặc đã ẩn hồ sơ');
    }

    const existing = await this.invitationRepo.findOne({
      where: { jobId: dto.jobId, candidateId: dto.candidateId },
    });
    if (existing) {
      throw new BadRequestException(
        'Bạn đã gửi thư mời cho ứng viên này vào vị trí này rồi',
      );
    }

    const invitation = this.invitationRepo.create({
      employerId: employer.id,
      candidateId: dto.candidateId,
      jobId: dto.jobId,
      message: dto.message,
      status: InvitationStatus.PENDING,
    });

    return this.invitationRepo.save(invitation);
  }

  async getSentInvitations(employerUserId: number) {
    const employer = await this.findEmployerByUserId(employerUserId);
    return this.invitationRepo.find({
      where: { employerId: employer.id },
      relations: ['candidate', 'job'],
      order: { createdAt: 'DESC' },
    });
  }

  private async findEmployerByUserId(userId: number): Promise<EmployerEntity> {
    const employer = await this.employerRepo.findOne({ where: { userId } });
    if (!employer) {
      throw new ForbiddenException('Tài khoản không phải nhà tuyển dụng');
    }
    if (!employer.companyId) {
      throw new ForbiddenException('Tài khoản chưa thuộc công ty nào');
    }
    return employer;
  }
}

import {
  Injectable,
  ForbiddenException,
  NotFoundException,
  BadRequestException,
  Logger,
} from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { DataSource, Repository } from 'typeorm';
import { JobEntity, JobStatus } from '../entities/job.entity';
import { JobStatusHistoryEntity } from '../entities/job-status-history.entity';
import { CreateJobDto } from '../dto/create-job.dto';
import { UpdateJobDto } from '../dto/update-job.dto';
import { JobFilterDto } from '../dto/job-filter.dto';
import { JobSkillsService } from '../job-skills.service';
import { EmployersService } from '../../employers/employers.service';
import { CompanyStatus } from '../../companies/entities/company.entity';
import { getPaginatedResult } from '../../common/utils/pagination.util';

@Injectable()
export class EmployerJobsService {
  private readonly logger = new Logger(EmployerJobsService.name);

  constructor(
    @InjectRepository(JobEntity)
    private readonly jobRepository: Repository<JobEntity>,
    @InjectRepository(JobStatusHistoryEntity)
    private readonly historyRepo: Repository<JobStatusHistoryEntity>,
    private readonly jobSkillsService: JobSkillsService,
    private readonly employersService: EmployersService,
    private readonly dataSource: DataSource,
  ) {}

  async createJob(employerUserId: number, createJobDto: CreateJobDto) {
    const employer = await this.employersService.getProfile(employerUserId);

    if (!employer.companyId) {
      throw new ForbiddenException(
        'Bạn phải tham gia vào một công ty trước khi đăng tin tuyển dụng',
      );
    }
    if (!employer.isAdminCompany) {
      throw new ForbiddenException(
        'Bạn không có quyền đăng tin (Yêu cầu tài khoản HR Admin)',
      );
    }

    try {
      return await this.dataSource.transaction(async (manager) => {
        const { skills, ...jobData } = createJobDto;

        const newJob = manager.create(JobEntity, {
          ...jobData,
          employerId: employer.id,
          companyId: employer.companyId,
          status: JobStatus.DRAFT,
        });
        const savedJob = await manager.save(newJob);

        await this.jobSkillsService.syncJobSkills(manager, savedJob.id, skills);

        return { id: savedJob.id, message: 'Đã tạo bản nháp tin tuyển dụng' };
      });
    } catch (e) {
      this.logger.error(e);
      throw new BadRequestException(
        'Không thể tạo tin tuyển dụng. Vui lòng kiểm tra lại thông tin.',
      );
    }
  }

  async updateJob(
    employerUserId: number,
    jobId: number,
    updateJobDto: UpdateJobDto,
  ) {
    const employer = await this.employersService.getProfile(employerUserId);

    if (!employer.isAdminCompany) {
      throw new ForbiddenException(
        'Bạn không có quyền chỉnh sửa tin (Yêu cầu tài khoản HR Admin)',
      );
    }

    const job = await this.jobRepository.findOne({
      where: { id: jobId, companyId: employer.companyId },
      relations: ['company'],
    });

    if (!job) {
      throw new NotFoundException(
        'Không tìm thấy tin tuyển dụng hoặc bạn không có quyền chỉnh sửa',
      );
    }

    const { status, ...otherJobData } = updateJobDto;

    // VALIDATE ALLOWED STATUS
    const employerAllowedStatuses = [
      JobStatus.DRAFT,
      JobStatus.PUBLISHED,
      JobStatus.CLOSED,
      JobStatus.PENDING,
    ];

    if (status && !employerAllowedStatuses.includes(status)) {
      throw new BadRequestException(
        `Nhà tuyển dụng không thể cập nhật tin sang trạng thái "${status}"`,
      );
    }

    const isCompanyVerified = job.company?.status === CompanyStatus.APPROVED;
    let finalStatus = (status as string) ?? job.status;

    if (status === (JobStatus.PUBLISHED as string) && !isCompanyVerified) {
      finalStatus = JobStatus.PENDING;
    }

    try {
      await this.dataSource.transaction(async (manager) => {
        const { skills, ...jobDataUpdates } = updateJobDto;
        delete jobDataUpdates.status; // handled above

        await manager.update(
          JobEntity,
          { id: jobId },
          { ...jobDataUpdates, status: finalStatus },
        );

        if (finalStatus !== job.status) {
          await manager.save(
            JobStatusHistoryEntity,
            manager.create(JobStatusHistoryEntity, {
              jobId,
              oldStatus: job.status,
              newStatus: finalStatus,
              reason: 'Nhà tuyển dụng thay đổi',
              changedById: employerUserId,
            }),
          );
        }

        if (skills) {
          await this.jobSkillsService.syncJobSkills(manager, jobId, skills);
        }
      });

      return {
        message:
          finalStatus === (JobStatus.PENDING as string)
            ? 'Tin đã được gửi duyệt. Vui lòng chờ Admin xác nhận.'
            : 'Cập nhật tin tuyển dụng thành công',
      };
    } catch (e) {
      this.logger.error(e);
      throw new BadRequestException('Lỗi cập nhật. Vui lòng thử lại.');
    }
  }

  async getEmployerJobs(employerUserId: number, filterDto: JobFilterDto) {
    const employer = await this.employersService.getProfile(employerUserId);

    if (!employer.companyId) return { data: [], total: 0 };

    const { page = 1, limit = 10, keyword, status } = filterDto;

    const qb = this.jobRepository
      .createQueryBuilder('job')
      .leftJoinAndSelect('job.category', 'category')
      .where('job.companyId = :companyId', { companyId: employer.companyId });

    if (keyword) {
      qb.andWhere('job.title ILIKE :keyword', { keyword: `%${keyword}%` });
    }

    if (status) {
      qb.andWhere('job.status = :status', { status });
    }

    qb.orderBy('job.createdAt', 'DESC');

    return getPaginatedResult(qb, page, limit);
  }

  async getEmployerJobHistory(employerUserId: number, jobId: number) {
    const employer = await this.employersService.getProfile(employerUserId);
    const job = await this.jobRepository.findOne({
      where: { id: jobId, companyId: employer.companyId },
    });

    if (!job) {
      throw new NotFoundException(
        'Tin tuyển dụng không tồn tại hoặc bạn không có quyền',
      );
    }

    return this.historyRepo.find({
      where: { jobId },
      order: { createdAt: 'DESC' },
    });
  }
}

import {
  BadRequestException,
  ConflictException,
  Injectable,
  Logger,
  NotFoundException,
} from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { DataSource, Repository } from 'typeorm';
import { EmployerEntity } from './entities/employer.entity';
import { CompanyEntity } from '../companies/entities/company.entity';
import { SetupCompanyDto } from './dto/setup-company.dto';
import { UpdateEmployerProfileDto } from './dto/update-employer-profile.dto';
import { SupabaseService } from '../storage/supabase.service';

@Injectable()
export class EmployersService {
  private readonly logger = new Logger(EmployersService.name);
  constructor(
    @InjectRepository(EmployerEntity)
    private readonly employerRepo: Repository<EmployerEntity>,
    @InjectRepository(CompanyEntity)
    private readonly companyRepo: Repository<CompanyEntity>,
    private readonly dataSource: DataSource,
    private readonly supabaseService: SupabaseService,
  ) {}

  async setupCompany(userId: number, dto: SetupCompanyDto) {
    const existingEmployer = await this.employerRepo.findOne({
      where: { userId },
    });
    if (existingEmployer) {
      throw new ConflictException('Tài khoản này đã khởi tạo hồ sơ');
    }

    const queryRunner = this.dataSource.createQueryRunner();
    await queryRunner.connect();
    await queryRunner.startTransaction();

    try {
      // 1. Create Company
      const company = queryRunner.manager.create(CompanyEntity, {
        userCreatorId: userId,
        categoryId: dto.categoryId,
        name: dto.companyName,
        provinceId: dto.provinceId,
        address: dto.address,
      });
      const savedCompany = await queryRunner.manager.save(company);

      // 2. Create Employer linked to User & Company
      const employer = queryRunner.manager.create(EmployerEntity, {
        userId,
        companyId: savedCompany.id,
        fullName: dto.fullName,
        phoneContact: dto.phoneContact,
        isAdminCompany: true,
      });
      const savedEmployer = await queryRunner.manager.save(employer);

      await queryRunner.commitTransaction();

      return {
        message: 'Khởi tạo công ty và hồ sơ HR thành công',
        employer: savedEmployer,
        company: savedCompany,
      };
    } catch (error: unknown) {
      this.logger.error('Lỗi trong quá trình khởi tạo công ty', error);
      await queryRunner.rollbackTransaction();
      throw new BadRequestException('Lỗi trong quá trình khởi tạo công ty');
    } finally {
      await queryRunner.release();
    }
  }

  async getProfile(userId: number) {
    const employer = await this.employerRepo.findOne({
      where: { userId },
      relations: ['company'],
    });

    if (!employer) {
      throw new NotFoundException(
        'Không tìm thấy thông tin tài khoản tuyển dụng',
      );
    }

    return employer;
  }

  async updateProfile(userId: number, dto: UpdateEmployerProfileDto) {
    const employer = await this.employerRepo.findOne({ where: { userId } });
    if (!employer) {
      throw new NotFoundException(
        'Không tìm thấy thông tin tài khoản tuyển dụng',
      );
    }

    Object.assign(employer, dto);
    await this.employerRepo.save(employer);
    return employer;
  }

  async uploadAvatar(userId: number, file: Express.Multer.File) {
    if (!file) {
      throw new BadRequestException('Chưa cung cấp file ảnh đại diện');
    }

    const employer = await this.employerRepo.findOne({ where: { userId } });
    if (!employer) {
      throw new NotFoundException(
        'Không tìm thấy thông tin tài khoản tuyển dụng',
      );
    }

    const originalName = file.originalname.replace(/\s+/g, '_');
    const uploadPath = `employers/avatars/${userId}-${Date.now()}-${originalName}`;

    const { publicUrl } = await this.supabaseService.atomicUploadAndUpdate(
      file,
      uploadPath,
      async (url) => {
        employer.avatarUrl = url;
        return this.employerRepo.save(employer);
      },
      employer.avatarUrl
        ? `employers/avatars/${employer.avatarUrl.split('/').pop()}`
        : undefined,
    );

    return {
      message: 'Cập nhật ảnh đại diện thành công',
      avatarUrl: publicUrl,
    };
  }
}

