@Injectable()
export class ProvincesService {
  constructor(
    @InjectRepository(ProvinceMetadataEntity)
    private readonly provinceRepository: Repository<ProvinceMetadataEntity>,
  ) {}

  async findAll(): Promise<ProvinceMetadataEntity[]> {
    return this.provinceRepository.find({
      order: {
        name: 'ASC',
      },
    });
  }

  async search(query: string): Promise<ProvinceMetadataEntity[]> {
    const trimmed = query.trim().toLowerCase();
    if (!trimmed) return this.findAll();

    return this.provinceRepository
      .createQueryBuilder('province')
      .where('LOWER(province.name) LIKE :q', { q: `%${trimmed}%` })
      .orWhere('LOWER(province.slug) LIKE :q', { q: `%${trimmed}%` })
      .orderBy('province.name', 'ASC')
      .getMany();
  }

  async findOne(id: string): Promise<ProvinceMetadataEntity> {
    const province = await this.provinceRepository.findOne({
      where: { code: id },
    });
    if (!province) {
      throw new NotFoundException(`Province with ID ${id} not found`);
    }
    return province;
  }
}

import { Injectable, NotFoundException } from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository } from 'typeorm';
import { JobEntity, JobStatus } from '../entities/job.entity';
import { JobFilterDto } from '../dto/job-filter.dto';
import { getPaginatedResult } from '../../common/utils/pagination.util';

@Injectable()
export class PublicJobsService {
  constructor(
    @InjectRepository(JobEntity)
    private readonly jobRepository: Repository<JobEntity>,
  ) {}

  async getPublicJobs(filterDto: JobFilterDto) {
    const {
      page = 1,
      limit = 10,
      keyword,
      provinceId,
      categoryId,
      jobTypeId,
    } = filterDto;

    const qb = this.jobRepository
      .createQueryBuilder('job')
      .leftJoin('job.company', 'company')
      .addSelect([
        'company.id',
        'company.name',
        'company.logoUrl',
        'company.bannerUrl',
        'company.description',
        'company.websiteUrl',
        'company.slug',
      ])
      .leftJoinAndSelect('job.province', 'province')
      .leftJoinAndSelect('job.category', 'category')
      .leftJoinAndSelect('job.jobType', 'jobType')
      .leftJoinAndSelect('job.skills', 'skillTag')
      .leftJoinAndSelect('skillTag.skillMetadata', 'skillMeta')
      .where('job.status = :status', { status: JobStatus.PUBLISHED });

    if (keyword) {
      qb.andWhere('job.title ILIKE :keyword', { keyword: `%${keyword}%` });
    }
    if (provinceId) {
      qb.andWhere('job.provinceId = :provinceId', { provinceId });
    }
    if (categoryId) {
      qb.andWhere('job.categoryId = :categoryId', { categoryId });
    }
    if (jobTypeId) {
      qb.andWhere('job.jobTypeId = :jobTypeId', { jobTypeId });
    }

    qb.orderBy('job.createdAt', 'DESC');

    return getPaginatedResult(qb, page, limit);
  }

  async getJobDetail(jobId: number) {
    const job = await this.jobRepository.findOne({
      where: { id: jobId, status: JobStatus.PUBLISHED },
      relations: [
        'company',
        'employer',
        'province',
        'category',
        'jobType',
        'skills',
        'skills.skillMetadata',
      ],
    });

    if (!job) {
      throw new NotFoundException('Tin tuyển dụng không tồn tại hoặc đã đóng');
    }

    const { company, employer, ...jobData } = job;

    // Lọc dữ liệu an toàn cho Company
    const safeCompany = company
      ? {
          id: company.id,
          name: company.name,
          emailContact: company.emailContact,
          phoneContact: company.phoneContact,
          address: company.address,
          provinceId: company.provinceId,
          logoUrl: company.logoUrl,
          bannerUrl: company.bannerUrl,
          description: company.description,
          content: company.content,
          companySize: company.companySize,
          websiteUrl: company.websiteUrl,
          facebookUrl: company.facebookUrl,
          linkedinUrl: company.linkedinUrl,
          slug: company.slug,
          images: company.images,
          createdAt: company.createdAt,
          updatedAt: company.updatedAt,
        }
      : null;

    // Lọc dữ liệu an toàn cho Employer
    const safeEmployer = employer
      ? {
          id: employer.id,
          fullName: employer.fullName,
          phoneContact: employer.phoneContact,
          avatarUrl: employer.avatarUrl,
          isAdminCompany: employer.isAdminCompany,
        }
      : null;

    return {
      ...jobData,
      company: safeCompany,
      employer: safeEmployer,
    };
  }
}

import { Injectable, Logger } from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository, In } from 'typeorm';
import { ConfigService } from '@nestjs/config';
import { GoogleGenerativeAI } from '@google/generative-ai';
import { SkillMetadataEntity, SkillType } from './skill-metadata.entity';
import { SKILL_STANDARDIZER_PROMPT } from './prompts/skill-standardizer.prompt';
import { toSlug } from '../../common/utils/string.util';

@Injectable()
export class SkillsMetadataService {
  private readonly logger = new Logger(SkillsMetadataService.name);
  private genAI: GoogleGenerativeAI;

  constructor(
    @InjectRepository(SkillMetadataEntity)
    private readonly skillMetadataRepository: Repository<SkillMetadataEntity>,
    private readonly configService: ConfigService,
  ) {
    const apiKey = this.configService.get<string>('GEMINI_API_KEY');
    if (apiKey) {
      this.genAI = new GoogleGenerativeAI(apiKey);
    }
  }

  /**
   * Search skills — exact match trước, fuzzy sau.
   * Dùng cho autocomplete (Phase 1).
   */
  async search(query: string, limit = 10) {
    const trimmed = query.trim().toLowerCase();
    if (!trimmed) return [];

    return this.skillMetadataRepository
      .createQueryBuilder('skill')
      .where('LOWER(skill.canonical_name) LIKE :q', { q: `%${trimmed}%` })
      .orWhere('skill.aliases::text ILIKE :q2', { q2: `%${trimmed}%` })
      .orderBy(
        `CASE WHEN LOWER(skill.canonical_name) = :exact THEN 0
              WHEN LOWER(skill.canonical_name) LIKE :startsWith THEN 1
              ELSE 2 END`,
      )
      .setParameters({ exact: trimmed, startsWith: `${trimmed}%` })
      .addOrderBy('skill.use_count', 'DESC')
      .limit(limit)
      .getMany();
  }

  /**
   * Tìm skill bằng slug (exact match).
   */
  async findBySlug(slug: string) {
    return this.skillMetadataRepository.findOne({ where: { slug } });
  }

  /**
   * Fuzzy search cho 1 raw skill name.
   * Tìm trong canonical_name + aliases.
   */
  async findByFuzzy(rawName: string) {
    const results = await this.findManyByFuzzy([rawName]);
    return results[0] || null;
  }

  /**
   * Batch fuzzy search cho nhiều raw skill names.
   * Giúp tránh lỗi N+1 query khi parse CV.
   */
  async findManyByFuzzy(rawNames: string[]): Promise<SkillMetadataEntity[]> {
    if (!rawNames.length) return [];
    const trimmedNames = rawNames.map((n) => n.trim()).filter((n) => n);
    if (!trimmedNames.length) return [];

    const slugs = trimmedNames.map((n) => toSlug(n));

    // 1. Tìm chính xác theo slug (Batch)
    const exactMatches = await this.skillMetadataRepository.find({
      where: { slug: In(slugs) },
    });

    const foundSlugs = new Set(exactMatches.map((m) => m.slug));
    const remainingNames = trimmedNames.filter(
      (n) => !foundSlugs.has(toSlug(n)),
    );

    if (remainingNames.length === 0) return exactMatches;

    // 2. Tìm fuzzy trong aliases (Sử dụng 1 query duy nhất với ANY)
    const fuzzyResults = await this.skillMetadataRepository
      .createQueryBuilder('skill')
      .where('skill.aliases::text ILIKE ANY(:queries)', {
        queries: remainingNames.map((n) => `%${n}%`),
      })
      .getMany();

    // Gộp kết quả và trả về (unique by ID)
    const allResults = [...exactMatches, ...fuzzyResults];
    const uniqueMap = new Map(allResults.map((r) => [r.id, r]));

    return Array.from(uniqueMap.values());
  }

  /**
   * Batch gọi AI Gemini để format + phân loại nhiều skills.
   */
  async formatWithAI(
    rawSkills: string[],
  ): Promise<{ name: string; type: SkillType }[]> {
    if (!this.genAI || rawSkills.length === 0) {
      // Fallback nếu không có API key: trim + title case
      return rawSkills.map((s) => ({
        name: s.trim(),
        type: SkillType.HARD,
      }));
    }

    try {
      const model = this.genAI.getGenerativeModel({
        model: 'gemini-2.5-flash',
      });

      const prompt = SKILL_STANDARDIZER_PROMPT(rawSkills);

      const result = await model.generateContent(prompt);
      const text = result.response.text().trim();
      this.logger.log(`AI Response: ${text}`);

      // Parse JSON from response
      const jsonMatch = text.match(/\[[\s\S]*\]/);
      if (!jsonMatch) {
        this.logger.warn('AI response is not valid JSON, using fallback');
        return rawSkills.map((s) => ({
          name: s.trim(),
          type: SkillType.HARD,
        }));
      }

      return JSON.parse(jsonMatch[0]) as { name: string; type: SkillType }[];
    } catch (error) {
      this.logger.error('AI formatting failed, using fallback', error);
      return rawSkills.map((s) => ({
        name: s.trim(),
        type: SkillType.HARD,
      }));
    }
  }

  /**
   * Upsert skill vào metadata.
   * Sử dụng ON CONFLICT (slug) để đảm bảo tính nhất quán (Atomicity).
   */
  async upsertSkill(
    name: string,
    type: SkillType,
    alias?: string,
  ): Promise<SkillMetadataEntity> {
    const slug = toSlug(name);
    const cleanAlias = alias?.trim();

    // Dùng QueryBuilder để thực hiện UPSERT (ON CONFLICT DO UPDATE)
    await this.skillMetadataRepository
      .createQueryBuilder()
      .insert()
      .into(SkillMetadataEntity)
      .values({
        canonicalName: name,
        slug,
        type,
        aliases: cleanAlias ? [cleanAlias] : [],
        useCount: 1,
      })
      .onConflict(
        `("slug") DO UPDATE SET 
         "use_count" = "skill_metadata"."use_count" + 1,
         "aliases" = CASE 
           WHEN NOT ("skill_metadata"."aliases" ? :alias) AND :alias IS NOT NULL 
           THEN "skill_metadata"."aliases" || jsonb_build_array(:alias)
           ELSE "skill_metadata"."aliases"
         END`,
      )
      .setParameter('alias', cleanAlias)
      .execute();

    return this.findBySlug(slug) as Promise<SkillMetadataEntity>;
  }

  /**
   * Tăng use_count cho skill đã biết.
   */
  async incrementUseCount(id: number) {
    await this.skillMetadataRepository.increment({ id }, 'useCount', 1);
  }

  /**
   * Find by ID.
   */
  async findById(id: number) {
    return this.skillMetadataRepository.findOne({ where: { id } });
  }

  /**
   * Find multiple by IDs.
   */
  async findByIds(ids: number[]) {
    if (!ids || ids.length === 0) return [];
    return this.skillMetadataRepository.find({ where: { id: In(ids) } });
  }

  /**
   * Tăng use_count cho nhiều skills.
   */
  async incrementUseCountBulk(ids: number[]) {
    if (!ids || ids.length === 0) return;
    await this.skillMetadataRepository.increment(
      { id: In(ids) },
      'useCount',
      1,
    );
  }
}

import {
  Injectable,
  InternalServerErrorException,
  Logger,
} from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import { createClient, SupabaseClient } from '@supabase/supabase-js';

export interface UploadFile {
  buffer: Buffer;
  mimetype: string;
  originalname: string;
  size: number;
}

@Injectable()
export class SupabaseService {
  private supabase: SupabaseClient<any, any, any>;
  private readonly logger = new Logger(SupabaseService.name);
  private bucketName: string;

  constructor(private configService: ConfigService) {
    const supabaseUrl = this.configService.get<string>('SUPABASE_PROJECT_URL');
    const supabaseKey = this.configService.get<string>('SUPABASE_SECRET_KEY');
    this.bucketName =
      this.configService.get<string>('SUPABASE_STORAGE_BUCKET') ||
      'ats_storage';
    if (!supabaseUrl || !supabaseKey || !this.bucketName) {
      this.logger.error(
        'Missing SUPABASE_PROJECT_URL or SUPABASE_SECRET_KEY or SUPABASE_STORAGE_BUCKET in environment variables',
      );
      throw new InternalServerErrorException('Missing Supabase configuration');
    }

    this.supabase = createClient(supabaseUrl, supabaseKey, {
      auth: {
        persistSession: false,
      },
    });
  }

  /**
   * Upload file to Supabase Storage
   * @param file The file wrapped by Multer
   * @param path The path where the file will be uploaded (e.g. 'cv/123.pdf')
   * @param overrideBucket Optional bucket name to override the default
   * @returns Public URL of the uploaded file
   */
  async uploadFile(
    file: UploadFile,
    path: string,
    overrideBucket?: string,
  ): Promise<string> {
    const bucket = overrideBucket || this.bucketName;

    // Check if bucket exists, if not create it (this requires sufficient permissions)
    // In production, it's safer to create buckets manually in the Supabase Dashboard.

    const { error } = await this.supabase.storage
      .from(bucket)
      .upload(path, file.buffer, {
        contentType: file.mimetype,
        upsert: true,
      });

    if (error) {
      this.logger.error(
        `Error uploading file to Supabase: ${(error as Error).message}`,
      );
      throw new InternalServerErrorException('Cập nhật file thất bại');
    }

    const { data: publicUrlData } = this.supabase.storage
      .from(bucket)
      .getPublicUrl(path);

    return publicUrlData.publicUrl;
  }

  /**
   * Remove a file from Supabase Storage
   * @param path The path of the file to remove
   */
  async deleteFile(path: string, overrideBucket?: string): Promise<void> {
    const bucket = overrideBucket || this.bucketName;
    const { error } = await this.supabase.storage.from(bucket).remove([path]);

    if (error) {
      this.logger.error(
        `Error deleting file from Supabase: ${(error as Error).message}`,
      );
      // Usually we might not throw if delete fails, depending on requirements,
      // but let's log it.
    }
  }

  /**
   * Helper to perform an atomic file upload and database update.
   * If the database update fails, the newly uploaded file is deleted.
   * If it succeeds, the old file (if provided) is deleted.
   * @param file The file to upload
   * @param uploadPath The path to upload to
   * @param updateDbCallback Callback function to perform the database update
   * @param oldFilePath Optional old file path to delete after successful update
   */
  async atomicUploadAndUpdate<T>(
    file: UploadFile,
    uploadPath: string,
    updateDbCallback: (publicUrl: string) => Promise<T>,
    oldFilePath?: string,
  ): Promise<{ result: T; publicUrl: string }> {
    const publicUrl = await this.uploadFile(file, uploadPath);

    try {
      const result = await updateDbCallback(publicUrl);

      // Orphan Fix: delete old file after successful save
      if (oldFilePath) {
        await this.deleteFile(oldFilePath).catch((e: Error) =>
          this.logger.error(`Error deleting old file: ${e.message}`),
        );
      }

      return { result, publicUrl };
    } catch (dbError) {
      // Orphan Fix: DB failed → delete newly uploaded file
      this.logger.error(
        `Database update failed, deleting orphaned file: ${uploadPath}`,
      );
      await this.deleteFile(uploadPath).catch(() => null);
      throw dbError;
    }
  }
}

