export enum JobStatus {
  DRAFT = 'draft',
  PENDING = 'pending',
  PUBLISHED = 'published',
  REJECTED = 'rejected',
  CLOSED = 'closed',
}

@Entity('job')
export class JobEntity {
  @PrimaryGeneratedColumn()
  id: number;

  @Index()
  @Column({ name: 'company_id' })
  companyId: number;

  @Index()
  @Column({ name: 'employer_id' })
  employerId: number;

  @Column({ type: 'varchar', length: 255 })
  title: string;

  @Column({ type: 'text' })
  description: string;

  @Column({ type: 'text', nullable: true })
  requirements: string;

  @Column({ type: 'text', nullable: true })
  benefits: string;

  @Column({
    name: 'salary_min',
    type: 'decimal',
    precision: 15,
    scale: 2,
    nullable: true,
  })
  salaryMin: number;

  @Column({
    name: 'salary_max',
    type: 'decimal',
    precision: 15,
    scale: 2,
    nullable: true,
  })
  salaryMax: number;

  @Column({ type: 'varchar', length: 10, default: 'VND' })
  currency: string;

  @Column({ name: 'years_of_experience', type: 'int', nullable: true })
  yearsOfExperience: number;

  @Index()
  @Column({ name: 'province_id', nullable: true })
  provinceId: number;

  @Index()
  @Column({ name: 'category_id', nullable: true })
  categoryId: number;

  @Index()
  @Column({ name: 'job_type_id', nullable: true })
  jobTypeId: number;

  @Index()
  @Column({ type: 'varchar', length: 20, default: JobStatus.DRAFT })
  status: string;

  @Column({ type: 'int', nullable: true })
  slots: number;

  @Column({ name: 'rejection_reason', type: 'text', nullable: true })
  rejectionReason: string | null;

  @Column({ type: 'timestamp', nullable: true })
  deadline: Date;

  @CreateDateColumn({ name: 'created_at' })
  createdAt: Date;

  @UpdateDateColumn({ name: 'updated_at' })
  updatedAt: Date;

  // -- RELATIONS --

  @ManyToOne(() => CompanyEntity)
  @JoinColumn({ name: 'company_id' })
  company: CompanyEntity;

  @ManyToOne(() => EmployerEntity)
  @JoinColumn({ name: 'employer_id' })
  employer: EmployerEntity;

  @ManyToOne(() => ProvinceMetadataEntity)
  @JoinColumn({ name: 'province_id' })
  province: ProvinceMetadataEntity;

  @ManyToOne(() => JobCategoryMetadataEntity)
  @JoinColumn({ name: 'category_id' })
  category: JobCategoryMetadataEntity;

  @ManyToOne(() => JobTypeMetadataEntity)
  @JoinColumn({ name: 'job_type_id' })
  jobType: JobTypeMetadataEntity;

  @OneToMany(() => JobSkillTagEntity, (skillTag) => skillTag.job, {
    cascade: ['insert', 'update', 'remove'],
  })
  skills: JobSkillTagEntity[];

  @OneToMany(() => JobApplicationEntity, (app) => app.job)
  applications: JobApplicationEntity[];
}

import { createZodDto } from 'nestjs-zod';
