export enum InvitationStatus {
  PENDING = 'pending',
  ACCEPTED = 'accepted',
  DECLINED = 'declined',
}

@Entity('job_invitation')
export class JobInvitationEntity {
  @PrimaryGeneratedColumn()
  id: number;

  @Column({ name: 'employer_id' })
